import { Calendar, MapPin, Clock, Building } from "lucide-react";
import { Link, useNavigate } from "react-router-dom";
import { Event, categoryColors } from "@/data/mockData";
import { motion } from "framer-motion";
import { useAuth } from "@/context/AuthContext";

interface EventCardProps {
  event: Event;
  index?: number;
  onRegister?: (id: string) => void;
  showPrice?: boolean;
}

const EventCard = ({ event, index = 0, onRegister, showPrice = true }: EventCardProps) => {
  const navigate = useNavigate();
  const { user } = useAuth();
  
  const eventId = event.id || (event as any)._id || "";
  const currentRegistered = event.registeredCount ?? event.registered ?? 0;
  const spotsLeft = event.maxParticipants - currentRegistered;
  const capacityPercent = (currentRegistered / event.maxParticipants) * 100;
  const isAlmostFull = capacityPercent >= 90;

  const displayImage = event.imageUrl || event.image || "https://images.unsplash.com/photo-1501281668745-f7f57925c3b4?w=600&h=400&fit=crop";
  const organizerDisplay = event.organizerName || event.organizer || "Campus Club";

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay: index * 0.1, ease: [0.25, 0.1, 0.25, 1] }}
      className="group bg-card rounded-2xl shadow-surface overflow-hidden transition-all duration-300 hover:shadow-surface-elevated hover:-translate-y-2 flex flex-col"
    >
      <Link to={`/events/${eventId}`} className="block relative">
        <div className="aspect-[16/10] relative overflow-hidden">
          <img
            src={displayImage}
            alt={event.title}
            className="object-cover w-full h-full group-hover:scale-110 transition-transform duration-700 ease-out"
            loading="lazy"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent opacity-60 group-hover:opacity-80 transition-opacity duration-300" />
          <div className="absolute top-4 left-4 flex flex-wrap gap-2">
            <span className={`${categoryColors[typeof event.category === 'string' ? event.category : event.category?.name] || "bg-muted text-muted-foreground"} px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wider shadow-sm backdrop-blur-md`}>
              {typeof event.category === 'string' ? event.category : event.category?.name || "Event"}
            </span>
            {event.trending && (
              <span className="bg-accent/90 text-accent-foreground px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wider shadow-sm backdrop-blur-md">
                ≡ƒöÑ Trending
              </span>
            )}
            {showPrice && (
              <span className={`px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wider shadow-sm backdrop-blur-md ${event.isPaidEvent ? "bg-primary text-primary-foreground" : "bg-green-500/90 text-white"}`}>
                {event.isPaidEvent ? `Γé╣${event.price}` : "Free"}
              </span>
            )}
          </div>
          {isAlmostFull && event.status === "open" && (
            <div className="absolute bottom-4 right-4">
              <span className="bg-destructive text-destructive-foreground px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wider shadow-md animate-pulse">
                Almost Full
              </span>
            </div>
          )}
        </div>
      </Link>
      <div className="p-6 flex flex-col flex-1">
        <Link to={`/events/${eventId}`}>
          <h3 className="text-xl font-bold text-card-foreground leading-tight group-hover:text-primary transition-colors duration-300 mb-3 line-clamp-2">
            {event.title}
          </h3>
        </Link>
        <div className="space-y-2.5 mb-5 flex-1">
          <div className="flex items-center text-sm text-muted-foreground gap-2.5">
            <Calendar className="w-4 h-4 text-primary shrink-0" />
            <span className="tabular-nums font-medium">{event.date}</span>
            <Clock className="w-4 h-4 text-primary shrink-0 ml-1" />
            <span className="font-medium">{event.time}</span>
          </div>
          <div className="flex items-center text-sm text-muted-foreground gap-2.5">
            <MapPin className="w-4 h-4 text-primary shrink-0" />
            <span className="truncate">{event.venue}</span>
          </div>
          <div className="flex items-center text-sm text-muted-foreground gap-2.5">
            <Building className="w-4 h-4 text-primary shrink-0" />
            <span className="truncate font-medium">{organizerDisplay}</span>
          </div>
        </div>
        <div className="mb-6">
          <div className="flex justify-between text-xs text-muted-foreground mb-2">
            <span className="font-semibold">{currentRegistered} / {event.maxParticipants} Registered</span>
            <span className={isAlmostFull && event.status === "open" ? "text-destructive font-bold" : "font-medium"}>
              {event.status === "open" ? `${spotsLeft} spots left` : event.status.toUpperCase()}
            </span>
          </div>
          <div className="h-2 bg-muted rounded-full overflow-hidden shadow-inner">
            <motion.div
              initial={{ width: 0 }}
              animate={{ width: `${capacityPercent}%` }}
              transition={{ duration: 1.2, delay: index * 0.1 + 0.3, ease: "easeOut" }}
              className={`h-full rounded-full ${isAlmostFull && event.status === "open" ? "bg-destructive" : "bg-primary"}`}
            />
          </div>
        </div>
        <div className="flex items-center justify-between gap-3 pt-4 border-t border-border">
          <Link
            to={`/events/${eventId}`}
            className="flex-1 text-center bg-secondary/10 text-secondary-foreground border border-secondary/20 px-4 py-2.5 rounded-xl text-sm font-semibold hover:bg-secondary/20 transition-all active:scale-[0.98]"
          >
            Details
          </Link>
          <button
            onClick={(e) => { 
                e.preventDefault(); 
                if (!user) {
                  navigate("/login", { state: { from: { pathname: "/student/explore" } } });
                  return;
                }
                if(onRegister) {
                   onRegister(eventId);
                } else {
                   navigate(`/events/${eventId}`);
                }
            }}
            disabled={event.status !== "open" || currentRegistered >= event.maxParticipants}
            className="flex-1 text-center bg-primary text-primary-foreground px-4 py-2.5 rounded-xl text-sm font-semibold hover:bg-primary/90 hover:shadow-lg hover:shadow-primary/30 transition-all active:scale-[0.98] disabled:opacity-50 disabled:bg-muted disabled:text-muted-foreground disabled:shadow-none"
          >
            {event.status !== "open" ? "Closed" : "Register"}
          </button>
        </div>
      </div>
    </motion.div>
  );
};

export default EventCard;

import { useEffect, useState, useRef } from "react";
import { LucideIcon } from "lucide-react";
import { motion } from "framer-motion";

interface StatCardProps {
  title: string;
  value: number;
  icon: LucideIcon;
  trend?: string;
  color?: string;
  delay?: number;
  suffix?: string;
}

const AnimatedNumber = ({ target, duration = 1200 }: { target: number; duration?: number }) => {
  const [current, setCurrent] = useState(0);
  const ref = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    let start = 0;
    const startTime = performance.now();
    const animate = (time: number) => {
      const elapsed = time - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setCurrent(Math.floor(eased * target));
      if (progress < 1) requestAnimationFrame(animate);
    };
    requestAnimationFrame(animate);
  }, [target, duration]);

  return <span ref={ref}>{current}</span>;
};

const StatCard = ({ title, value, icon: Icon, trend, color = "text-primary", delay = 0, suffix = "" }: StatCardProps) => (
  <motion.div
    initial={{ opacity: 0, y: 20, scale: 0.95 }}
    animate={{ opacity: 1, y: 0, scale: 1 }}
    transition={{ duration: 0.4, delay, ease: [0.25, 0.1, 0.25, 1] }}
    className="bg-card rounded-xl shadow-surface p-6 transition-all duration-300 hover:shadow-surface-hover hover-lift group"
  >
    <div className="flex items-start justify-between">
      <div>
        <p className="text-sm text-muted-foreground font-medium">{title}</p>
        <p className="text-3xl font-bold text-card-foreground mt-1 tabular-nums">
          <AnimatedNumber target={typeof value === "number" ? value : parseInt(String(value))} />
          {suffix}
        </p>
        {trend && (
          <p className="text-xs text-accent font-semibold mt-2 flex items-center gap-1">
            <svg className="w-3 h-3" viewBox="0 0 12 12" fill="none"><path d="M6 2L10 7H2L6 2Z" fill="currentColor" /></svg>
            {trend}
          </p>
        )}
      </div>
      <div className={`p-3 rounded-xl bg-muted ${color} group-hover:scale-110 transition-transform duration-300`}>
        <Icon className="w-5 h-5" />
      </div>
    </div>
  </motion.div>
);

export default StatCard;

import { useState, useEffect, useRef } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import {
  LayoutDashboard, Compass, CalendarCheck, User, LogOut,
  PlusCircle, Settings, BarChart3, Users, Menu, X, Moon, Sun,
  Layers, Bell, Search, ChevronLeft, ChevronRight, LayoutGrid,
  CalendarRange, Check
} from "lucide-react";
import { useAuth } from "@/context/AuthContext";
import { api } from "@/lib/api";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";

interface NavItem {
  title: string;
  url: string;
  icon: React.ElementType;
}

const studentNav: NavItem[] = [
  { title: "Dashboard", url: "/student", icon: LayoutDashboard },
  { title: "Explore Events", url: "/student/explore", icon: Compass },
  { title: "My Registrations", url: "/student/registrations", icon: CalendarCheck },
  { title: "Categories", url: "/student/explore#categories", icon: Layers },
  { title: "Notifications", url: "/notifications", icon: Bell },
  { title: "Settings", url: "/settings", icon: Settings },
];

const adminNav: NavItem[] = [
  { title: "Dashboard", url: "/admin", icon: LayoutDashboard },
  { title: "Create Event", url: "/admin/create", icon: PlusCircle },
  { title: "Manage Events", url: "/admin/manage", icon: CalendarRange },
  { title: "Event Participants", url: "/admin/registrations", icon: Users },
  { title: "Analytics", url: "/admin/analytics", icon: BarChart3 },
  { title: "Categories", url: "/admin/categories", icon: LayoutGrid },
  { title: "Settings", url: "/admin/settings", icon: Settings },
];

interface DashboardLayoutProps {
  children: React.ReactNode;
  role: "student" | "admin";
}

const DashboardLayout = ({ children, role }: DashboardLayoutProps) => {
  const { user, logout, token } = useAuth();
  const [isCollapsed, setIsCollapsed] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isNotifOpen, setIsNotifOpen] = useState(false);
  const [notifications, setNotifications] = useState<any[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const location = useLocation();
  const navigate = useNavigate();
  const dropdownRef = useRef<HTMLDivElement>(null);
  const notifRef = useRef<HTMLDivElement>(null);

  const navItems = role === "admin" ? adminNav : studentNav;

  useEffect(() => {
    const fetchNotifs = async () => {
      if (user?.id) {
        try {
          const response = await api.get(`/notifications/${user.id}`, token || undefined);
          if (response.success) {
            setNotifications(response.data);
          }
        } catch (error) {
          console.error("Notifs fetch error", error);
        }
      }
    };
    fetchNotifs();
    const interval = setInterval(fetchNotifs, 30000); // 30s update
    return () => clearInterval(interval);
  }, [user?.id, token]);

  const unreadCount = notifications.filter(n => !n.readStatus).length;

  const handleLogout = () => {
    logout();
    navigate("/");
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/student/explore?q=${encodeURIComponent(searchQuery)}`);
    }
  };

  const markAsRead = async (id: string) => {
    try {
      await api.put(`/notifications/${id}/read`, {}, token || undefined);
      setNotifications(prev => prev.map(n => n.id === id ? { ...n, readStatus: true } : n));
    } catch (error) {
       console.error(error);
    }
  };

  return (
    <TooltipProvider>
      <div className="flex h-screen bg-background overflow-hidden font-sans">
        {/* Sidebar - Desktop */}
        <motion.aside
          initial={false}
          animate={{ width: isCollapsed ? 80 : 280 }}
          className="hidden lg:flex flex-col bg-[#1E293B] text-slate-300 border-r border-slate-800 z-50 relative shadow-2xl"
        >
          {/* Logo Section */}
          <div className="h-20 flex items-center px-5 border-b border-white/5">
            <Link to="/" className="flex items-center gap-3.5 min-w-[200px] group">
              <div className="w-10 h-10 bg-gradient-to-br from-primary to-indigo-600 rounded-xl flex items-center justify-center text-white shadow-xl shadow-primary/20 group-hover:rotate-6 transition-all duration-500">
                <CalendarRange className="w-6 h-6" />
              </div>
              {!isCollapsed && (
                <motion.div 
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  className="flex flex-col"
                >
                  <span className="font-black text-xl text-white tracking-tighter">Eventra</span>
                  <span className="text-[10px] text-primary font-black uppercase tracking-widest">Dashboard</span>
                </motion.div>
              )}
            </Link>
          </div>

          {/* Nav Items */}
          <div className="flex-1 overflow-y-auto overflow-x-hidden py-6 px-4 space-y-2.5 custom-scrollbar">
            {navItems.map((item) => {
              const active = location.pathname === item.url;
              return (
                <Tooltip key={item.url} delayDuration={0}>
                  <TooltipTrigger asChild>
                    <Link
                      to={item.url}
                      className={`flex items-center gap-4 px-4 py-3.5 rounded-2xl transition-all relative group ${
                        active 
                          ? "bg-primary text-white shadow-xl shadow-primary/30" 
                          : "hover:bg-slate-800/80 hover:text-white"
                      }`}
                    >
                      <item.icon className={`w-5 h-5 shrink-0 transition-transform group-hover:scale-110 ${active ? "text-white" : "text-slate-400 group-hover:text-white"}`} />
                      {!isCollapsed && (
                        <motion.span 
                          initial={{ opacity: 0, x: -10 }}
                          animate={{ opacity: 1, x: 0 }}
                          className={`font-bold text-sm whitespace-nowrap ${active ? "text-white" : "text-slate-300"}`}
                        >
                          {item.title}
                        </motion.span>
                      )}
                      {item.title === "Notifications" && unreadCount > 0 && !isCollapsed && (
                        <span className="ml-auto bg-accent text-accent-foreground text-[10px] font-extrabold px-2 py-0.5 rounded-full">
                          {unreadCount}
                        </span>
                      )}
                      {active && !isCollapsed && (
                         <motion.div layoutId="activeNav" className="absolute left-[-16px] w-1.5 h-8 bg-white rounded-r-full shadow-[0_0_15px_rgba(255,255,255,0.5)]" />
                      )}
                    </Link>
                  </TooltipTrigger>
                  {isCollapsed && (
                    <TooltipContent side="right" className="bg-slate-900 border-slate-800 text-white font-bold text-xs py-2 px-3">
                      <div className="flex items-center gap-2">
                        {item.title}
                        {item.title === "Notifications" && unreadCount > 0 && (
                          <span className="bg-accent w-2 h-2 rounded-full" />
                        )}
                      </div>
                    </TooltipContent>
                  )}
                </Tooltip>
              );
            })}
          </div>

          {/* Bottom Section */}
          <div className="p-4 border-t border-slate-800/50 space-y-3">
             <button
              onClick={handleLogout}
              className="flex items-center gap-4 w-full px-4 py-3.5 rounded-2xl text-slate-400 hover:bg-destructive/10 hover:text-destructive transition-all group font-bold"
            >
              <LogOut className="w-5 h-5 shrink-0 group-hover:scale-110 transition-transform" />
              {!isCollapsed && <span className="text-sm">Logout</span>}
            </button>
          </div>

          {/* Toggle Button */}
          <button 
            onClick={() => setIsCollapsed(!isCollapsed)}
            className="absolute -right-4 top-24 w-8 h-8 bg-primary text-white rounded-full flex items-center justify-center shadow-2xl border-4 border-background hover:scale-110 active:scale-90 transition-all z-[60]"
          >
            {isCollapsed ? <ChevronRight className="w-4 h-4" /> : <ChevronLeft className="w-4 h-4" />}
          </button>
        </motion.aside>

        {/* Mobile Sidebar Overlay */}
        <AnimatePresence>
          {isMobileMenuOpen && (
            <>
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={() => setIsMobileMenuOpen(false)}
                className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] lg:hidden"
              />
              <motion.aside
                initial={{ x: "-100%" }}
                animate={{ x: 0 }}
                exit={{ x: "-100%" }}
                transition={{ type: "spring", damping: 25, stiffness: 200 }}
                className="fixed top-0 left-0 h-full w-[280px] bg-[#1E293B] z-[101] lg:hidden flex flex-col p-4"
              >
                <div className="flex items-center justify-between mb-8 px-2">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-primary rounded-xl flex items-center justify-center text-white font-bold">E</div>
                    <span className="font-bold text-xl text-white">Eventra</span>
                  </div>
                  <button onClick={() => setIsMobileMenuOpen(false)} className="p-2 text-slate-400 hover:text-white">
                    <X className="w-6 h-6" />
                  </button>
                </div>
                <nav className="flex-1 space-y-2">
                  {navItems.map((item) => (
                    <Link
                      key={item.url}
                      to={item.url}
                      onClick={() => setIsMobileMenuOpen(false)}
                      className={`flex items-center gap-4 px-4 py-3 rounded-xl transition-all ${
                        location.pathname === item.url 
                          ? "bg-primary text-white font-bold shadow-lg" 
                          : "text-slate-400 hover:bg-slate-800 hover:text-white"
                      }`}
                    >
                      <item.icon className="w-5 h-5" />
                      <span>{item.title}</span>
                    </Link>
                  ))}
                </nav>
                <button
                  onClick={handleLogout}
                  className="flex items-center gap-4 px-4 py-3 text-destructive rounded-xl hover:bg-destructive/10 transition-all font-bold mt-4 border-t border-slate-800 pt-6"
                >
                  <LogOut className="w-5 h-5" />
                  <span>Logout</span>
                </button>
              </motion.aside>
            </>
          )}
        </AnimatePresence>

        {/* Main Content Area */}
        <div className="flex-1 flex flex-col h-screen overflow-hidden relative">
          {/* Header */}
          <header className="h-16 flex items-center justify-between px-4 lg:px-8 border-b border-border bg-background/80 backdrop-blur-md sticky top-0 z-40 shrink-0">
            <div className="flex items-center gap-4">
              <button 
                onClick={() => setIsMobileMenuOpen(true)}
                className="lg:hidden p-2 text-foreground hover:bg-muted rounded-lg transition-colors"
              >
                <Menu className="w-6 h-6" />
              </button>

              {/* Search Bar - ChatGPT style */}
              <div className="hidden md:flex relative group w-64 lg:w-96">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                <form onSubmit={handleSearch} className="w-full">
                  <input
                    type="text"
                    placeholder="Search events, venues..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-muted/50 border border-transparent focus:bg-background focus:border-primary/30 rounded-full text-sm outline-none ring-primary/10 focus:ring-4 transition-all"
                  />
                </form>
              </div>
            </div>

            <div className="flex items-center gap-3 lg:gap-5">
              {/* Notifications */}
              <div className="relative" ref={notifRef}>
                <button
                  onClick={() => setIsNotifOpen(!isNotifOpen)}
                  className={`p-2.5 rounded-full transition-all relative active:scale-95 ${
                    isNotifOpen ? "bg-primary/10 text-primary" : "text-muted-foreground hover:text-foreground hover:bg-muted"
                  }`}
                >
                  <Bell className="w-5 h-5" />
                  {unreadCount > 0 && (
                    <span className="absolute top-2 right-2 flex items-center justify-center min-w-[18px] h-[18px] px-1 bg-accent text-white text-[10px] font-bold rounded-full border-2 border-background shadow-sm">
                      {unreadCount}
                    </span>
                  )}
                </button>

                <AnimatePresence>
                  {isNotifOpen && (
                    <motion.div
                      initial={{ opacity: 0, y: 10, scale: 0.95 }}
                      animate={{ opacity: 1, y: 0, scale: 1 }}
                      exit={{ opacity: 0, y: 10, scale: 0.95 }}
                      className="absolute right-0 mt-3 w-80 sm:w-96 bg-card border border-border rounded-2xl shadow-surface-elevated z-[100] overflow-hidden p-2"
                    >
                      <div className="px-4 py-3 border-b border-border/50 flex items-center justify-between">
                        <h3 className="font-bold text-sm">Notifications</h3>
                        {unreadCount > 0 && (
                          <span className="text-[10px] bg-primary/10 text-primary px-2 py-0.5 rounded-full font-bold">
                            {unreadCount} New
                          </span>
                        )}
                      </div>
                      <div className="max-h-[400px] overflow-y-auto py-2 custom-scrollbar">
                        {notifications.length === 0 ? (
                          <div className="py-12 text-center">
                            <Bell className="w-10 h-10 text-muted-foreground/30 mx-auto mb-3" />
                            <p className="text-xs text-muted-foreground">Catch up later! No new alerts.</p>
                          </div>
                        ) : (
                          notifications.map((n) => (
                            <div 
                              key={n.id} 
                              className={`px-4 py-3 rounded-xl mb-1 transition-colors relative group ${!n.readStatus ? 'bg-primary/5 hover:bg-primary/10' : 'hover:bg-muted/50'}`}
                            >
                              <div className="flex gap-4">
                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${!n.readStatus ? 'bg-primary/10 text-primary' : 'bg-muted text-muted-foreground'}`}>
                                  <Bell className="w-5 h-5" />
                                </div>
                                <div className="flex-1 min-w-0">
                                  <p className={`text-[13px] leading-snug ${!n.readStatus ? 'font-bold text-foreground' : 'text-muted-foreground'}`}>{n.message}</p>
                                  <p className="text-[10px] text-muted-foreground mt-1.5 flex items-center gap-1.5 font-medium">
                                    <span className="w-1 h-1 bg-muted-foreground/30 rounded-full" />
                                    {new Date(n.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                                  </p>
                                </div>
                                {!n.readStatus && (
                                  <button 
                                    onClick={() => markAsRead(n.id)}
                                    className="opacity-0 group-hover:opacity-100 p-1.5 hover:bg-primary/10 rounded-lg transition-all self-center"
                                    title="Mark as read"
                                  >
                                    <Check className="w-4 h-4 text-primary" />
                                  </button>
                                )}
                              </div>
                            </div>
                          ))
                        )}
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>

              {/* Profile Wrapper */}
              <div className="relative" ref={dropdownRef}>
                <button 
                  onClick={() => setIsProfileOpen(!isProfileOpen)}
                  className={`flex items-center gap-3 p-1 pl-3 pr-1 rounded-full border transition-all active:scale-95 ${
                    isProfileOpen ? "border-primary bg-primary/5 shadow-inner" : "border-border hover:bg-muted"
                  }`}
                >
                  <div className="hidden lg:block text-right">
                    <p className="text-xs font-black text-foreground leading-none">{user?.name?.split(" ")[0]}</p>
                    <p className="text-[10px] text-primary uppercase font-black tracking-tighter mt-1">{role}</p>
                  </div>
                  <div className="w-9 h-9 rounded-full bg-gradient-to-br from-primary/20 to-primary/10 border border-primary/20 flex items-center justify-center text-primary font-black overflow-hidden shadow-sm">
                    {user?.picture ? (
                       <img src={user.picture} alt={user.name} className="w-full h-full object-cover" />
                    ) : (
                      user?.name?.charAt(0) || "U"
                    )}
                  </div>
                </button>

                {/* Dropdown Menu */}
                <AnimatePresence>
                  {isProfileOpen && (
                    <motion.div
                      initial={{ opacity: 0, scale: 0.95, y: 10 }}
                      animate={{ opacity: 1, scale: 1, y: 0 }}
                      exit={{ opacity: 0, scale: 0.95, y: 10 }}
                      className="absolute right-0 mt-3 w-64 bg-card border border-border rounded-2xl shadow-surface-elevated overflow-hidden z-[100] p-2"
                    >
                      <div className="px-4 py-4 border-b border-border/50 mb-1">
                        <p className="text-sm font-bold text-foreground truncate">{user?.name}</p>
                        <p className="text-xs text-muted-foreground truncate">{user?.email}</p>
                        <div className="mt-2 flex">
                          <span className="bg-primary/10 text-primary px-2 py-0.5 rounded-lg text-[10px] font-extrabold uppercase tracking-widest border border-primary/20">
                            {user?.role} Account
                          </span>
                        </div>
                      </div>
                      <div className="space-y-0.5">
                        <Link to={role === "admin" ? "/admin" : "/student"} onClick={() => setIsProfileOpen(false)} className="flex items-center gap-3 px-3 py-2.5 text-sm font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-xl transition-all">
                          <LayoutDashboard className="w-4 h-4 text-primary" /> Dashboard
                        </Link>
                        <Link to={role === "admin" ? "/profile" : "/student/profile"} onClick={() => setIsProfileOpen(false)} className="flex items-center gap-3 px-3 py-2.5 text-sm font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-xl transition-all">
                          <User className="w-4 h-4 text-primary" /> My Profile
                        </Link>
                        {role === "admin" && (
                          <>
                            <Link to="/admin/create" onClick={() => setIsProfileOpen(false)} className="flex items-center gap-3 px-3 py-2.5 text-sm font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-xl transition-all">
                              <PlusCircle className="w-4 h-4 text-primary" /> Create Event
                            </Link>
                            <Link to="/admin/manage" onClick={() => setIsProfileOpen(false)} className="flex items-center gap-3 px-3 py-2.5 text-sm font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-xl transition-all">
                              <Settings className="w-4 h-4 text-primary" /> Manage Events
                            </Link>
                          </>
                        )}
                        <Link to="/settings" onClick={() => setIsProfileOpen(false)} className="flex items-center gap-3 px-3 py-2.5 text-sm font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-xl transition-all">
                          <Settings className="w-4 h-4 text-primary" /> Settings
                        </Link>
                      </div>
                      <button onClick={handleLogout} className="w-full flex items-center gap-3 px-3 py-2.5 text-sm font-bold text-destructive hover:bg-destructive/10 rounded-xl transition-all mt-1 border-t border-border/50 pt-3">
                        <LogOut className="w-4 h-4" /> Logout
                      </button>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>
          </header>

          {/* Page Content */}
          <main className="flex-1 overflow-y-auto overflow-x-hidden p-4 lg:p-10 scroll-smooth bg-muted/20">
            <motion.div
              key={location.pathname}
              initial={{ opacity: 0, y: 15 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, ease: [0.25, 0.1, 0.25, 1] }}
              className="max-w-7xl mx-auto"
            >
              {children}
            </motion.div>
          </main>
        </div>
      </div>
    </TooltipProvider>
  );
};

export default DashboardLayout;

import { useState, useEffect, useRef } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { 
  Search, Menu, X, Bell, LayoutDashboard, Calendar, 
  Settings, LogOut, Check, CalendarRange, Info, 
  Mail, Zap, Compass, PlusCircle, BarChart3, 
  ChevronDown, User as UserIcon, Moon, Sun, 
  Ticket, Sparkles
} from "lucide-react";
import { useAuth } from "@/context/AuthContext";
import { motion, AnimatePresence } from "framer-motion";
import { api } from "@/lib/api";
import { toast } from "sonner";

const Navbar = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isNotifOpen, setIsNotifOpen] = useState(false);
  const [notifications, setNotifications] = useState<any[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [scrolled, setScrolled] = useState(false);
  const { user, token, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const dropdownRef = useRef<HTMLDivElement>(null);
  const notifRef = useRef<HTMLDivElement>(null);

  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll);

    if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setIsDark(true);
      document.documentElement.classList.add('dark');
    }

    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsProfileOpen(false);
      }
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) {
        setIsNotifOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      window.removeEventListener("scroll", handleScroll);
    };
  }, []);

  useEffect(() => {
    const fetchNotifs = async () => {
      if (user?.id) {
        try {
          const response = await api.get(`/notifications/${user.id}`, token || undefined);
          if (response.success) setNotifications(response.data);
        } catch (error) {
          console.error("Notifs fetch error", error);
        }
      }
    };
    if (user) {
      fetchNotifs();
      const interval = setInterval(fetchNotifs, 60000);
      return () => clearInterval(interval);
    }
  }, [user?.id, token]);

  const toggleTheme = () => {
    const newDark = !isDark;
    setIsDark(newDark);
    document.documentElement.classList.toggle('dark', newDark);
    localStorage.theme = newDark ? 'dark' : 'light';
  };

  const getNavLinks = () => {
    if (!user) {
      return [
        { title: "Home", url: "/#", icon: Ticket },
        { title: "Features", url: "/#features", icon: Zap },
        { title: "Events", url: "/#events", icon: Calendar },
        { title: "About", url: "/#about", icon: Info },
        { title: "Contact", url: "/#contact", icon: Mail },
      ];
    }
    if (user.role === "admin") {
      return [
        { title: "Explore", url: "/student/explore", icon: Compass },
        { title: "Create", url: "/admin/create", icon: PlusCircle },
        { title: "Manage", url: "/admin/manage", icon: Settings },
        { title: "Analytics", url: "/admin/analytics", icon: BarChart3 },
      ];
    }
    return [
      { title: "Explore Events", url: "/student/explore", icon: Compass },
      { title: "My Registrations", url: "/student/registrations", icon: Ticket },
      { title: "Categories", url: "/student/explore#categories", icon: LayoutDashboard },
    ];
  };

  const navLinks = getNavLinks();

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/student/explore?q=${encodeURIComponent(searchQuery)}`);
      setIsMobileMenuOpen(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate("/");
    setIsProfileOpen(false);
    setIsMobileMenuOpen(false);
    toast.success("Logged out successfully");
  };

  const handleGoogleLogin = () => {
    navigate("/login?google=true");
  };

  const logoIcon = (
    <div className="w-10 h-10 bg-gradient-to-br from-primary to-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary/20 group-hover:shadow-primary/40 transition-all duration-500 group-hover:rotate-6">
      <CalendarRange className="w-6 h-6" />
    </div>
  );

  return (
    <nav 
      className={`fixed top-0 z-[100] w-full transition-all duration-500 ${
        scrolled 
          ? "bg-background/80 backdrop-blur-xl border-b border-border py-2 shadow-lg" 
          : "bg-transparent py-4 text-foreground"
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex items-center justify-between">

        {/* Left Side: Logo */}
        <Link to={user ? (user.role === "admin" ? "/admin" : "/student") : "/"} className="flex items-center gap-3 group relative z-10">
          {logoIcon}
          <div className="flex flex-col">
            <span className="font-black text-2xl tracking-tighter text-foreground leading-none group-hover:text-primary transition-colors">Eventra</span>
            {!user && (
              <span className="text-[10px] font-bold text-primary uppercase tracking-[0.2em] mt-0.5 opacity-80">
                Campus Events
              </span>
            )}
            {user && (
              <span className="text-[10px] font-black text-primary uppercase tracking-widest mt-0.5">
                {user.role} Hub
              </span>
            )}
          </div>
        </Link>

        {/* Center: Desktop Links */}
        <div className="hidden lg:flex items-center justify-center gap-1 bg-muted/20 p-1 rounded-2xl border border-border/50 backdrop-blur-md">
          {navLinks.map((link) => (
            <Link 
              key={link.title} 
              to={link.url}
              className={`px-4 py-2 text-sm font-bold rounded-xl transition-all flex items-center gap-2 ${
                location.pathname === link.url.split('#')[0]
                  ? "bg-background text-primary shadow-sm"
                  : "text-muted-foreground hover:text-foreground hover:bg-background/50"
              }`}
            >
              {link.title}
            </Link>
          ))}
        </div>

        {/* Right Side */}
        <div className="hidden lg:flex items-center justify-end gap-3 min-w-[200px]">
          {user ? (
            <div className="flex items-center gap-3">
              {/* Search */}
              <form onSubmit={handleSearch} className="relative group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                <input
                  type="text"
                  placeholder="Search..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-32 xl:w-48 pl-9 pr-4 py-2 bg-muted/30 border border-transparent focus:bg-background focus:border-primary/30 rounded-full text-xs outline-none focus:ring-4 focus:ring-primary/10 transition-all"
                />
              </form>

              {/* Theme Toggle */}
              <button onClick={toggleTheme} className="p-2 text-muted-foreground hover:text-foreground hover:bg-muted rounded-full transition-all">
                {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
              </button>

              {/* Notifications */}
              <div className="relative" ref={notifRef}>
                <button 
                  onClick={() => setIsNotifOpen(!isNotifOpen)}
                  className={`p-2 rounded-full transition-all relative ${isNotifOpen ? 'bg-primary/10 text-primary' : 'text-muted-foreground hover:bg-muted'}`}
                >
                  <Bell className="w-5 h-5" />
                  {notifications.some(n => !n.readStatus) && (
                    <span className="absolute top-1.5 right-1.5 w-2.5 h-2.5 bg-accent rounded-full border-2 border-background animate-pulse" />
                  )}
                </button>
                <AnimatePresence>
                  {isNotifOpen && (
                    <motion.div 
                      initial={{ opacity: 0, y: 10, scale: 0.95 }}
                      animate={{ opacity: 1, y: 0, scale: 1 }}
                      exit={{ opacity: 0, y: 10, scale: 0.95 }}
                      className="absolute right-0 mt-3 w-80 bg-card border border-border rounded-3xl shadow-surface-elevated overflow-hidden z-[200] p-2"
                    >
                      <div className="px-4 py-3 border-b border-border/50 flex justify-between items-center">
                        <span className="font-black text-xs uppercase tracking-widest">Notifications</span>
                        <div className="w-2 h-2 bg-primary rounded-full" />
                      </div>
                      <div className="max-h-80 overflow-y-auto py-2 custom-scrollbar space-y-1">
                        {notifications.length === 0 ? (
                          <div className="py-10 text-center opacity-50"><Sparkles className="w-8 h-8 mx-auto mb-2" /><p className="text-xs font-bold">All caught up!</p></div>
                        ) : (
                          notifications.map(n => (
                            <div key={n.id} className={`p-3 rounded-2xl transition-all ${!n.readStatus ? 'bg-primary/5' : 'opacity-60 hover:opacity-100 hover:bg-muted'}`}>
                              <p className="text-xs font-bold leading-snug">{n.message}</p>
                              <p className="text-[10px] mt-1 font-medium opacity-50">{new Date(n.createdAt).toLocaleDateString()}</p>
                            </div>
                          ))
                        )}
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>

              {/* Profile Wrapper */}
              <div className="relative" ref={dropdownRef}>
                <button 
                  onClick={() => setIsProfileOpen(!isProfileOpen)}
                  className="flex items-center gap-2 p-1.5 bg-muted/30 border border-border/50 rounded-full hover:border-primary/30 transition-all hover:bg-primary/5 active:scale-95"
                >
                  <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary/20 to-primary/10 flex items-center justify-center text-primary font-black overflow-hidden border border-primary/20">
                    {user?.picture ? <img src={user.picture} alt="" className="w-full h-full object-cover" /> : user?.name.charAt(0)}
                  </div>
                  <ChevronDown className={`w-4 h-4 transition-transform ${isProfileOpen ? 'rotate-180' : ''}`} />
                </button>
                <AnimatePresence>
                  {isProfileOpen && (
                    <motion.div 
                      initial={{ opacity: 0, y: 10, scale: 0.95 }}
                      animate={{ opacity: 1, y: 0, scale: 1 }}
                      exit={{ opacity: 0, y: 10, scale: 0.95 }}
                      className="absolute right-0 mt-3 w-64 bg-card border border-border rounded-3xl shadow-surface-elevated overflow-hidden z-[200] p-2"
                    >
                      <div className="p-4 border-b border-border/50 mb-2">
                        <p className="font-black text-sm">{user?.name}</p>
                        <p className="text-[11px] font-bold opacity-50 truncate">{user?.email}</p>
                        <div className="mt-2 text-[9px] font-black uppercase tracking-tighter bg-primary/10 text-primary w-fit px-2 py-0.5 rounded-md">
                          {user?.role} Account
                        </div>
                      </div>
                      <div className="space-y-0.5">
                        <Link to={user?.role === "admin" ? "/admin" : "/student"} className="flex items-center gap-3 px-3 py-2.5 text-xs font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-xl transition-all" onClick={() => setIsProfileOpen(false)}>
                          <LayoutDashboard className="w-4 h-4" /> Dashboard
                        </Link>
                        <Link to="/profile" className="flex items-center gap-3 px-3 py-2.5 text-xs font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-xl transition-all" onClick={() => setIsProfileOpen(false)}>
                          <UserIcon className="w-4 h-4" /> Profile Details
                        </Link>
                        <Link to="/settings" className="flex items-center gap-3 px-3 py-2.5 text-xs font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-xl transition-all" onClick={() => setIsProfileOpen(false)}>
                          <Settings className="w-4 h-4" /> Account Settings
                        </Link>
                      </div>
                      <button onClick={handleLogout} className="w-full flex items-center gap-3 px-3 py-2.5 text-xs font-black text-destructive hover:bg-destructive/10 rounded-xl transition-all mt-2 border-t border-border/50 pt-3">
                        <LogOut className="w-4 h-4" /> Sign Out
                      </button>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>
          ) : (
            <div className="flex items-center gap-3">
              <Link to="/login" className="text-sm font-black text-muted-foreground hover:text-foreground px-4 py-2 transition-all">
                Login
              </Link>
              <button 
                onClick={handleGoogleLogin} 
                className="hidden xl:flex items-center gap-2 bg-card border border-border px-4 py-2.5 rounded-xl text-xs font-bold hover:shadow-lg transition-all active:scale-95"
              >
                <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="" className="w-4 h-4" />
                Google Login
              </button>
              <Link to="/register" className="bg-primary text-primary-foreground px-6 py-2.5 rounded-xl text-xs font-black shadow-lg shadow-primary/30 hover:shadow-primary/50 hover:-translate-y-0.5 transition-all active:scale-95">
                Register
              </Link>
            </div>
          )}
        </div>

        {/* Mobile Toggle */}
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="lg:hidden p-2 bg-muted/50 rounded-xl z-20">
          {isMobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <>
            <motion.div 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setIsMobileMenuOpen(false)}
              className="fixed inset-0 bg-background/60 backdrop-blur-md z-[150] lg:hidden"
            />
            <motion.div 
              initial={{ x: "100%" }} animate={{ x: 0 }} exit={{ x: "100%" }}
              transition={{ type: "spring", damping: 25, stiffness: 200 }}
              className="fixed right-0 top-0 h-full w-[300px] bg-background border-l border-border z-[160] shadow-2xl p-6 flex flex-col"
            >
              <div className="flex items-center gap-3 mb-10">
                {logoIcon}
                <span className="font-black text-xl tracking-tighter">Eventra</span>
              </div>

              <div className="flex flex-col gap-2 flex-1 overflow-y-auto">
                {navLinks.map((link) => (
                  <Link 
                    key={link.title} to={link.url}
                    onClick={() => setIsMobileMenuOpen(false)}
                    className="flex items-center gap-4 px-4 py-4 rounded-2xl text-sm font-black text-muted-foreground hover:text-foreground hover:bg-muted transition-all"
                  >
                    <link.icon className="w-5 h-5 text-primary" />
                    {link.title}
                  </Link>
                ))}
              </div>

              <div className="pt-6 border-t border-border mt-auto">
                {user ? (
                  <div className="space-y-3">
                    <div className="flex items-center gap-3 p-4 bg-primary/5 rounded-2xl border border-primary/10 mb-4">
                      <div className="w-10 h-10 rounded-xl bg-primary flex items-center justify-center text-white font-black overflow-hidden shadow-lg shadow-primary/20">
                         {user.picture ? <img src={user.picture} alt="" /> : user.name.charAt(0)}
                      </div>
                      <div className="min-w-0">
                        <p className="font-black text-sm truncate">{user.name}</p>
                        <p className="text-[10px] font-bold uppercase opacity-50">{user.role}</p>
                      </div>
                    </div>
                    <Link to={user.role === "admin" ? "/admin" : "/student"} onClick={() => setIsMobileMenuOpen(false)} className="block w-full text-center py-4 bg-muted font-black text-sm rounded-2xl">Dashboard</Link>
                    <button onClick={handleLogout} className="w-full py-4 text-destructive font-black text-sm rounded-2xl hover:bg-destructive/10 transition-all">Sign Out</button>
                  </div>
                ) : (
                  <div className="grid grid-cols-2 gap-3">
                    <Link to="/login" onClick={() => setIsMobileMenuOpen(false)} className="py-4 text-center font-black text-sm bg-muted rounded-2xl">Login</Link>
                    <Link to="/register" onClick={() => setIsMobileMenuOpen(false)} className="py-4 text-center font-black text-sm bg-primary text-white rounded-2xl shadow-lg shadow-primary/20">Sign Up</Link>
                  </div>
                )}
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive: "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline: "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props} />;
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

import * as React from "react";
import { type DialogProps } from "@radix-ui/react-dialog";
import { Command as CommandPrimitive } from "cmdk";
import { Search } from "lucide-react";

import { cn } from "@/lib/utils";
import { Dialog, DialogContent } from "@/components/ui/dialog";

const Command = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive>
>(({ className, ...props }, ref) => (
  <CommandPrimitive
    ref={ref}
    className={cn(
      "flex h-full w-full flex-col overflow-hidden rounded-md bg-popover text-popover-foreground",
      className,
    )}
    {...props}
  />
