interface User {
  id: string;
  name: string;
  email: string;
  role: "student" | "admin";
  picture?: string;
  authProvider?: string;
  createdAt?: string;
  department?: string;
}

interface AuthContextType {
  user: User | null;
  token: string | null;
  login: (token: string) => Promise<User>;
  logout: () => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const checkAuth = async () => {
      const savedToken = localStorage.getItem("eventra_token");
      if (savedToken) {
        try {
          // Verify token by fetching profile
          const response = await api.get("/users/profile", savedToken);
          if (response.success) {
            setToken(savedToken);
            setUser(response.data);
            localStorage.setItem("eventra_user", JSON.stringify(response.data));
          } else {
            // Token expired or invalid
            logout();
          }
        } catch (error) {
          console.error("Auth sync failed:", error);
          // If server is down, fallback to local data but keep token
          const savedUser = localStorage.getItem("eventra_user");
          if (savedUser) {
            setToken(savedToken);
            setUser(JSON.parse(savedUser));
          }
        }
      }
      setIsLoading(false);
    };

    checkAuth();
  }, []);

  const login = async (newToken: string) => {
    setToken(newToken);
    localStorage.setItem("eventra_token", newToken);

    try {
      const response = await api.get("/users/profile", newToken);
      if (response.success) {
        setUser(response.data);
        localStorage.setItem("eventra_user", JSON.stringify(response.data));
        return response.data;
      }
    } catch (error) {
      console.error("Failed to fetch user profile after login:", error);
      throw error;
    }
  };

  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem("eventra_token");
    localStorage.removeItem("eventra_user");
  };

  return (
    <AuthContext.Provider value={{ user, token, login, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

