const API_URL = "http://localhost:8000/api";

export const api = {
  get: async (endpoint: string, token?: string) => {
    try {
      const response = await fetch(`${API_URL}${endpoint}`, {
        headers: {
          Authorization: token ? `Bearer ${token}` : "",
        },
      });
      const data = await response.json();
      if (!response.ok && !data.success) {
        return { success: false, message: data.message || "Request failed", ...data };
      }
      return data;
    } catch (error) {
      console.error("API GET Error:", error);
      throw error;
    }
  },
  post: async (endpoint: string, data: any, token?: string) => {
    try {
      const response = await fetch(`${API_URL}${endpoint}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: token ? `Bearer ${token}` : "",
        },
        body: JSON.stringify(data),
      });

      const responseData = await response.json();

      if (!response.ok && !responseData.success) {
        return { 
          success: false, 
          message: responseData.message || `Server error (${response.status})`, 
          ...responseData 
        };
      }
      return responseData;
    } catch (error) {
      console.error("API POST Error:", error);
      throw error;
    }
  },
  put: async (endpoint: string, data: any, token?: string) => {
    try {
      const response = await fetch(`${API_URL}${endpoint}`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: token ? `Bearer ${token}` : "",
        },
        body: JSON.stringify(data),
      });
      const responseData = await response.json();
      if (!response.ok && !responseData.success) {
        return { success: false, message: responseData.message || "Update failed", ...responseData };
      }
      return responseData;
    } catch (error) {
      console.error("API PUT Error:", error);
      throw error;
    }
  },
  delete: async (endpoint: string, token?: string) => {
    try {
      const response = await fetch(`${API_URL}${endpoint}`, {
        method: "DELETE",
        headers: {
          Authorization: token ? `Bearer ${token}` : "",
        },
      });
      const data = await response.json();
      if (!response.ok && !data.success) {
        return { success: false, message: data.message || "Delete failed", ...data };
      }
      return data;
    } catch (error) {
      console.error("API DELETE Error:", error);
      throw error;
    }
  },
};

