export default Landing;

import { useState, useEffect } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { motion } from "framer-motion";
import { Eye, EyeOff, CalendarRange } from "lucide-react";
import { toast } from "sonner";
import { api } from "@/lib/api";
import { useAuth } from "@/context/AuthContext";
import { GoogleLogin } from "@react-oauth/google";

const Login = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();
  const { login, user } = useAuth();

  // Redirect already authenticated users
  useEffect(() => {
    if (user) {
      navigate(user.role === "admin" ? "/admin" : "/student", { replace: true });
    }
  }, [user, navigate]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    
    try {
      const response = await api.post("/auth/login", { email, password });
      
      if (response.success) {
        toast.success("Login successful!");
        const { access_token } = response.data;
        const freshUser = await login(access_token);
        
        // Redirect back to where they were going, or dashboard
        const from = (location.state as any)?.from?.pathname || (freshUser.role === "admin" ? "/admin" : "/student");
        navigate(from, { replace: true });
      } else {
        toast.error(response.message || "Invalid credentials");
      }
    } catch (error) {
      toast.error("Failed to connect to server");
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSuccess = async (credentialResponse: any) => {
    setLoading(true);
    try {
      const response = await api.post("/auth/google", { token: credentialResponse.credential });
      if (response.success) {
        toast.success("Google login successful!");
        const { access_token } = response.data;
        const freshUser = await login(access_token);
        const from = (location.state as any)?.from?.pathname || (freshUser.role === "admin" ? "/admin" : "/student");
        navigate(from, { replace: true });
      } else {
        toast.error(response.message || "Google login failed");
      }
    } catch (error) {
      toast.error("Google authentication failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex bg-background">
      {/* Left side - branding */}
      <div className="hidden lg:flex lg:w-1/2 bg-secondary relative overflow-hidden items-center justify-center">
        <div className="absolute inset-0 bg-gradient-to-br from-primary/20 to-accent/10" />
        <div className="absolute top-20 left-20 w-72 h-72 bg-primary/10 rounded-full blur-3xl" />
        <div className="absolute bottom-20 right-20 w-96 h-96 bg-accent/10 rounded-full blur-3xl" />
