export default AdminDashboard;

import { useState, useEffect } from "react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { categoryColors } from "@/data/mockData";
import { toast } from "sonner";
import { motion } from "framer-motion";
import { Search, Loader2, Star } from "lucide-react";
import { api } from "@/lib/api";
import { useAuth } from "@/context/AuthContext";

const ManageEvents = () => {
  const { token } = useAuth();
  const [events, setEvents] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  const fetchEvents = async () => {
    setLoading(true);
    try {
      const response = await api.get("/events");
      if (response.success) {
        setEvents(response.data);
      }
    } catch (error) {
      toast.error("Failed to load events");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchEvents();
  }, []);

  const handleUpdateStatus = async (id: string, newStatus: string) => {
    try {
      const response = await api.put(`/events/${id}`, { status: newStatus }, token || undefined);
      if (response.success) {
        toast.success(`Event ${newStatus}`);
        fetchEvents();
      }
    } catch (error) {
      toast.error("Status update failed");
    }
  };

  const handleToggleFeatured = async (id: string, isFeatured: boolean) => {
    try {
      const response = await api.put(`/events/${id}`, { isFeatured }, token || undefined);
      if (response.success) {
        toast.success(isFeatured ? "Marked as Featured" : "Removed from Featured");
        fetchEvents();
      }
    } catch (error) {
      toast.error("Update failed");
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Are you sure you want to delete this event?")) return;
    try {
      const response = await api.delete(`/events/${id}`, token || undefined);
      if (response.success) {
        toast.success("Event deleted");
        fetchEvents();
      }
    } catch (error) {
      toast.error("Delete failed");
    }
  };

  const filtered = events.filter((e) =>
    e.title.toLowerCase().includes(search.toLowerCase()) ||
    e.category.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <DashboardLayout role="admin">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-foreground">Manage Events</h1>
        <p className="text-sm text-muted-foreground mt-1">Edit, delete, or close registrations for your events.</p>
      </div>

      <div className="mb-6">
        <div className="relative max-w-md">
          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <input
            type="text"
            placeholder="Search events..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 bg-card border border-input rounded-xl text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring shadow-surface"
          />
        </div>
      </div>

      {loading ? (
        <div className="py-20 flex flex-col items-center">
          <Loader2 className="w-8 h-8 text-primary animate-spin mb-4" />
          <p className="text-muted-foreground animate-pulse">Fetching event fleet...</p>
        </div>
      ) : (
        <motion.div
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-card rounded-xl shadow-surface overflow-hidden"
        >
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-border bg-muted/50">
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Event Name</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Category</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Date</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Participants</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Status</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Featured</th>
                  <th className="text-right py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((event, i) => {
                  const currentRegistered = event.registeredCount ?? event.registered ?? 0;
                  const capacity = (currentRegistered / event.maxParticipants) * 100;
                  return (
                    <motion.tr
                      key={event.id}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ delay: i * 0.03 }}
                      className="border-b border-border last:border-0 hover:bg-muted/30 transition-colors group"
                    >
                      <td className="py-3.5 px-5">
                        <div className="flex items-center gap-3">
                          <img src={event.imageUrl || event.image} alt="" className="w-10 h-10 rounded-lg object-cover shrink-0" />
                          <span className="font-medium text-card-foreground">{event.title}</span>
                        </div>
                      </td>
                      <td className="py-3.5 px-5">
                        <span className={`${categoryColors[typeof event.category === 'string' ? event.category : event.category?.name] || "bg-muted text-muted-foreground"} px-2 py-0.5 rounded-md text-[11px] font-bold uppercase tracking-wider`}>
                          {typeof event.category === 'string' ? event.category : event.category?.name || "Event"}
                        </span>
                      </td>
                      <td className="py-3.5 px-5 text-muted-foreground tabular-nums">{event.date}</td>
                      <td className="py-3.5 px-5">
                        <div className="flex items-center gap-2">
                          <div className="w-16 h-1.5 bg-muted rounded-full overflow-hidden">
                            <div className={`h-full rounded-full ${capacity >= 90 ? "bg-destructive" : "bg-primary"}`} style={{ width: `${capacity}%` }} />
                          </div>
                          <span className="text-xs text-muted-foreground tabular-nums">{currentRegistered}/{event.maxParticipants}</span>
                        </div>
                      </td>
                      <td className="py-3.5 px-5">
                        <span className={`px-2.5 py-1 rounded-md text-[11px] font-bold uppercase tracking-wider ${
                          event.status === "open" ? "bg-accent/10 text-accent" :
                          event.status === "closed" ? "bg-amber-100 text-amber-700" :
                          "bg-muted text-muted-foreground"
                        }`}>
                          {event.status}
                        </span>
                      </td>
                      <td className="py-3.5 px-5">
                        <button
                          onClick={() => handleToggleFeatured(event.id, !event.isFeatured)}
                          className={`p-2 rounded-lg transition-all ${event.isFeatured ? "bg-amber-100 text-amber-600" : "bg-muted text-muted-foreground hover:bg-muted-foreground/10"}`}
                          title={event.isFeatured ? "Featured" : "Mark as Featured"}
                        >
                           <Star className={`w-4 h-4 ${event.isFeatured ? "fill-current" : ""}`} />
                        </button>
                      </td>
                      <td className="py-3.5 px-5 text-right">
                        <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => toast.info("Edit event coming soon")} className="px-2.5 py-1.5 text-xs font-medium text-primary hover:bg-primary/10 rounded-lg transition-colors">
                            Edit
                          </button>
                          {event.status === "open" ? (
                            <button onClick={() => handleUpdateStatus(event.id, "closed")} className="px-2.5 py-1.5 text-xs font-medium text-amber-600 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-lg transition-colors">
                              Close
                            </button>
                          ) : (
                            <button onClick={() => handleUpdateStatus(event.id, "open")} className="px-2.5 py-1.5 text-xs font-medium text-accent hover:bg-accent/10 rounded-lg transition-colors">
                              Open
                            </button>
                          )}
                          <button onClick={() => handleDelete(event.id)} className="px-2.5 py-1.5 text-xs font-medium text-destructive hover:bg-destructive/10 rounded-lg transition-colors">
                            Delete
                          </button>
                        </div>
                      </td>
                    </motion.tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          {filtered.length === 0 && (
            <div className="py-12 text-center text-muted-foreground text-sm">No events found.</div>
          )}
        </motion.div>
      )}
    </DashboardLayout>
  );
};

export default ManageEvents;

import { useState, useEffect } from "react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { Search, Loader2, QrCode, CheckCircle2 } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { api } from "@/lib/api";
import { useAuth } from "@/context/AuthContext";
import { toast } from "sonner";
import { Scanner } from '@yudiel/react-qr-scanner';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";

const AdminRegistrations = () => {
  const { token } = useAuth();
  const [registrations, setRegistrations] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");
  const [scannerOpen, setScannerOpen] = useState(false);

  const fetchRegistrations = async () => {
    setLoading(true);
    try {
      const response = await api.get("/registrations", token || undefined);
      if (response.success) {
        setRegistrations(response.data);
      }
    } catch (error) {
      toast.error("Failed to fetch registrations");
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRegistrations();
  }, [token]);

  const handleCheckIn = async (regId: string) => {
    try {
      const response = await api.put(`/registrations/${regId}/checkin`, {}, token || undefined);
      if (response.success) {
        toast.success("Student checked in successfully!");
        setScannerOpen(false);
        fetchRegistrations();
      } else {
        toast.error(response.message || "Failed to check in");
      }
    } catch (error: any) {
      toast.error(error?.response?.data?.detail || "Error checking in");
    }
  };

  const handleScan = (detectedCodes: any[]) => {
    if (detectedCodes.length > 0) {
      const scannedValue = detectedCodes[0].rawValue;
      if (scannedValue) {
        // Try check in
        handleCheckIn(scannedValue);
      }
    }
  };

  const filtered = registrations.filter((r) => {
    const matchesSearch = 
      r.studentName?.toLowerCase().includes(search.toLowerCase()) ||
      r.studentEmail?.toLowerCase().includes(search.toLowerCase()) ||
      r.eventName?.toLowerCase().includes(search.toLowerCase());
    
    const matchesStatus = statusFilter === "All" || r.status?.toLowerCase() === statusFilter.toLowerCase();
    
    return matchesSearch && matchesStatus;
  });

  return (
    <DashboardLayout role="admin">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-foreground">Registrations</h1>
        <p className="text-sm text-muted-foreground mt-1">View all student registrations across events ΓÇö {registrations.length} total.</p>
      </div>

      <div className="mb-6 flex flex-col sm:flex-row gap-4 justify-between items-start sm:items-center">
        <div className="flex flex-1 flex-col sm:flex-row gap-4 w-full">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <input
              type="text"
              placeholder="Search by student, email, or event..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-card border border-input rounded-xl text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 shadow-surface"
            />
          </div>
          <select 
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="px-4 py-2.5 bg-card border border-input rounded-xl text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 shadow-surface"
          >
            <option value="All">All Statuses</option>
            <option value="confirmed">Confirmed</option>
            <option value="waitlisted">Waitlisted</option>
            <option value="cancelled">Cancelled</option>
          </select>
        </div>
        <button
          onClick={() => setScannerOpen(true)}
          className="flex items-center gap-2 bg-primary text-primary-foreground px-4 py-2.5 rounded-xl text-sm font-bold shadow-lg shadow-primary/20 hover:shadow-primary/40 transition-all active:scale-95"
        >
          <QrCode className="w-5 h-5" />
          Scan QR Ticket
        </button>
      </div>

      {loading ? (
        <div className="py-20 flex flex-col items-center">
          <Loader2 className="w-8 h-8 text-primary animate-spin mb-4" />
          <p className="text-muted-foreground animate-pulse">Loading registrations...</p>
        </div>
      ) : (
        <motion.div
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-card rounded-xl shadow-surface overflow-hidden"
        >
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-border bg-muted/50">
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Student Name</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Email</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Event Name</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Req Status</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Check-in</th>
                  <th className="text-right py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Action</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((reg, i) => (
                  <motion.tr
                    key={reg.id}
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    transition={{ delay: i * 0.03 }}
                    className="border-b border-border last:border-0 hover:bg-muted/30 transition-colors"
                  >
                    <td className="py-3.5 px-5">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-primary/10 text-primary flex items-center justify-center text-xs font-bold shrink-0">
                          {(reg.studentName || "U").split(" ").map((n: string) => n[0]).join("")}
                        </div>
                        <span className="font-medium text-card-foreground">{reg.studentName}</span>
                      </div>
                    </td>
                    <td className="py-3.5 px-5 text-muted-foreground">{reg.studentEmail}</td>
                    <td className="py-3.5 px-5 text-card-foreground font-medium">{reg.eventName}</td>
                  <td className="py-3.5 px-5">
                    <span className={`px-2.5 py-1 rounded-md text-[11px] font-bold uppercase tracking-wider ${
                      reg.status === "confirmed" ? "bg-accent/10 text-accent" :
                      reg.status === "waitlisted" ? "bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300" :
                      "bg-destructive/10 text-destructive"
                    }`}>
                      {reg.status || reg.registrationStatus || "Unknown"}
                    </span>
                  </td>
                  <td className="py-3.5 px-5">
                    {reg.attendanceStatus === "present" ? (
                      <span className="flex items-center gap-1.5 text-xs font-bold text-green-600 dark:text-green-400">
                        <CheckCircle2 className="w-4 h-4" /> Present
                      </span>
                    ) : (
                      <span className="text-xs font-bold text-muted-foreground">Pending</span>
                    )}
                  </td>
                  <td className="py-3.5 px-5 text-right">
                    {reg.attendanceStatus !== "present" && (
                       <button
                         onClick={() => handleCheckIn(reg.id)}
                         className="text-xs font-bold text-primary hover:underline"
                       >
                         Mark Present
                       </button>
                    )}
                  </td>
                </motion.tr>
              ))}
            </tbody>
          </table>
        </div>
        {filtered.length === 0 && (
          <div className="py-12 text-center text-muted-foreground text-sm">No registrations found matching your search.</div>
        )}
      </motion.div>
      )}
      {/* QR Scanner Modal */}
      <Dialog open={scannerOpen} onOpenChange={setScannerOpen}>
        <DialogContent className="max-w-md p-6">
          <DialogHeader>
            <DialogTitle className="text-xl font-black mb-4">Scan Participant Ticket</DialogTitle>
          </DialogHeader>
          <div className="bg-muted rounded-xl overflow-hidden aspect-square border border-border">
            {scannerOpen && (
              <Scanner 
                onScan={handleScan}
                formats={['qr_code']}
              />
            )}
          </div>
          <p className="text-xs text-muted-foreground text-center mt-4">
            Position the QR code within the frame to automatically check in the student.
          </p>
        </DialogContent>
      </Dialog>
    </DashboardLayout>
  );
};

export default AdminRegistrations;

import { useState, useEffect } from "react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import StatCard from "@/components/StatCard";
import EventCard from "@/components/EventCard";
import { 
  CalendarDays, CalendarCheck, Clock, TrendingUp, 
  ArrowRight, Loader2, MapPin, Calendar, Users, Star, 
  Sparkles, ChevronRight, Zap, Target, Trophy, Flame, CheckCircle
} from "lucide-react";
import { toast } from "sonner";
import { motion, AnimatePresence } from "framer-motion";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "@/context/AuthContext";
import { api } from "@/lib/api";

const StudentDashboard = () => {
  const { user, token } = useAuth();
  const navigate = useNavigate();
  const [featuredEvent, setFeaturedEvent] = useState<any>(null);
  const [trendingEvents, setTrendingEvents] = useState<any[]>([]);
  const [registrations, setRegistrations] = useState<any[]>([]);
  const [upcomingEvents, setUpcomingEvents] = useState<any[]>([]);
  const [leaderboard, setLeaderboard] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const [featRes, trendRes, regsRes, allRes, leadRes] = await Promise.all([
        api.get("/events/featured"),
        api.get("/events/trending"),
        api.get(`/registrations/user/${user?.id}`, token || undefined),
        api.get("/events"),
        api.get("/analytics/leaderboard")
      ]);

      if (featRes.success) setFeaturedEvent(featRes.data);
      if (trendRes.success) setTrendingEvents(trendRes.data);
      if (regsRes.success) setRegistrations(regsRes.data);
      if (allRes.success) {
        // exclude featured from upcoming, show max 6
        const featId = featRes.data?.id || featRes.data?._id;
        setUpcomingEvents(allRes.data.filter((e: any) => (e.id || e._id) !== featId).slice(0, 6));
      }
      if (leadRes.success) setLeaderboard(leadRes.data);
    } catch (error) {
      toast.error("Dashboard synchronization slow...");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user?.id) {
      fetchDashboardData();
    }
  }, [user?.id, token]);

  if (loading) {
    return (
      <DashboardLayout role="student">
        <div className="min-h-[70vh] flex flex-col items-center justify-center">
          <div className="relative">
