        </div>

        {/* Sidebar */}
        <div className="lg:col-span-1 space-y-12">
           {/* Discover Section */}
           <div className="bg-card rounded-[2.5rem] border border-border/50 p-8 shadow-xl shadow-foreground/5 relative overflow-hidden">
