              <div className="space-y-4">
                {[
                  { label: "Cultural Events", icon: Trophy, count: 12, color: "text-amber-500", bg: "bg-amber-500/10" },
                  { label: "Tech Summits", icon: Zap, count: 8, color: "text-blue-500", bg: "bg-blue-500/10" },
                  { label: "Sports Meet", icon: Target, count: 5, color: "text-emerald-500", bg: "bg-emerald-500/10" },
                ].map((item, i) => (
                  <button key={i} className="w-full flex items-center justify-between p-4 rounded-3xl bg-muted/30 hover:bg-muted transition-all border border-transparent hover:border-border group">
