              <Link to="/student/explore" className="mt-10 w-full flex items-center justify-center py-4 bg-muted text-foreground hover:bg-foreground hover:text-background rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">
                Browse Categories
