           {/* Daily Leaderboard */}
           <div className="bg-card rounded-[2.5rem] border border-border/50 p-8 shadow-xl shadow-foreground/5 relative overflow-hidden">
               <div className="flex items-center justify-between mb-8">
                  <h3 className="text-2xl font-black tracking-tight flex items-center gap-3">Top Participants <Trophy className="w-6 h-6 text-yellow-500" /></h3>
