                    <div key={u.id} className={`flex items-center gap-4 p-3 rounded-2xl transition-all border border-transparent ${i === 0 ? 'bg-amber-500/10 border-amber-500/20 shadow-inner' : 'bg-muted/30 hover:bg-muted'}`}>
