export default StudentDashboard;

import { useParams, Link, useNavigate } from "react-router-dom";
import { categoryColors } from "@/data/mockData";
import { Calendar, Clock, MapPin, Users, User, ArrowLeft, Share2, Heart, CheckCircle2, Loader2, MessageSquare, Send } from "lucide-react";
import { motion } from "framer-motion";
import { toast } from "sonner";
import { useState, useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { api } from "@/lib/api";

const EventDetails = () => {
  const { id } = useParams();
  const { user, token } = useAuth();
  const navigate = useNavigate();
  const [event, setEvent] = useState<any>(null);
  const [countdown, setCountdown] = useState({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [wishlistLoading, setWishlistLoading] = useState(false);
  const [registered, setRegistered] = useState(false);
  const [isWishlisted, setIsWishlisted] = useState(false);
  const [participants, setParticipants] = useState<any[]>([]);
  const [allEvents, setAllEvents] = useState<any[]>([]);
  const [comments, setComments] = useState<any[]>([]);
  const [newComment, setNewComment] = useState("");
  const [commentLoading, setCommentLoading] = useState(false);

  const fetchEventData = async () => {
    if (!id) return;
    setLoading(true);
    try {
      const [eventRes, allRes, commentsRes] = await Promise.all([
        api.get(`/events/${id}`),
        api.get("/events"),
        api.get(`/comments/event/${id}`)
      ]);
      
      if (eventRes.success) {
        setEvent(eventRes.data);
      }
      
      if (allRes.success) {
        setAllEvents(allRes.data);
      }
      
      if (commentsRes.success) {
        setComments(commentsRes.data);
      }
      
      if (user?.id) {
        // Check registration and wishlist
        const [regsRes, wishRes] = await Promise.all([
           api.get(`/registrations/user/${user.id}`, token || undefined),
           api.get(`/wishlist/user/${user.id}`, token || undefined)
        ]);

        if (regsRes.success) {
          const isReg = regsRes.data.some((r: any) => r.eventId === id && r.registrationStatus === "confirmed");
          setRegistered(isReg);
        }

        if (wishRes.success) {
          const isWish = wishRes.data.some((w: any) => (w.id || w._id) === id);
          setIsWishlisted(isWish);
        }

        // Fetch participants for admin/organizer
        if (user.role === "admin" || user.id === eventRes.data?.organizerId) {
          const partRes = await api.get(`/events/${id}/participants`, token || undefined);
          if (partRes.success) {
            setParticipants(partRes.data);
          }
        }
      }
    } catch (error) {
      toast.error("Failed to load event details");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchEventData();
  }, [id, user?.id, token]);

  useEffect(() => {
    if (!event) return;
    const target = new Date(event.date + "T" + (event.time.includes("AM") || event.time.includes("PM") ? "10:00:00" : event.time));
    const interval = setInterval(() => {
      const now = new Date();
      const diff = target.getTime() - now.getTime();
      if (diff <= 0) { clearInterval(interval); return; }
      setCountdown({
        days: Math.floor(diff / 86400000),
        hours: Math.floor((diff % 86400000) / 3600000),
        minutes: Math.floor((diff % 3600000) / 60000),
        seconds: Math.floor((diff % 60000) / 1000),
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [event]);

  if (loading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-background">
        <Loader2 className="w-12 h-12 text-primary animate-spin mb-4" />
        <p className="text-muted-foreground animate-pulse font-medium">Loading event details...</p>
      </div>
    );
  }

  if (!event) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <div className="text-center">
          <h2 className="text-xl font-bold text-foreground mb-2">Event not found</h2>
          <Link to="/student/explore" className="text-primary text-sm hover:underline">ΓåÉ Back to events</Link>
        </div>
      </div>
    );
  }

  const handleCommentSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newComment.trim() || !user) return;
    
    setCommentLoading(true);
    try {
      const response = await api.post("/comments", { eventId: id, text: newComment }, token || undefined);
      if (response.success) {
        setComments([response.data, ...comments]);
        setNewComment("");
        toast.success("Comment posted");
      }
    } catch (error) {
      toast.error("Failed to post comment");
    } finally {
      setCommentLoading(false);
    }
  };

  const currentRegistered = event.registeredCount ?? event.registered ?? 0;
  const spotsLeft = event.maxParticipants - currentRegistered;
  const capacityPercent = (currentRegistered / event.maxParticipants) * 100;

  const handleRegister = async () => {
    if (!user) {
      navigate("/login", { state: { from: { pathname: window.location.pathname } } });
      return;
    }
    
    if (registered) {
      toast.error("You are already registered for this event.");
      return;
    }

    if (spotsLeft <= 0) {
      toast.error("Event registration closed because capacity is full.");
      return;
    }

    setActionLoading(true);
    try {
      const response = await api.post("/registrations", { eventId: event.id || event._id }, token || undefined);
      
      if (response.success) {
        setRegistered(true);
        toast.success("Successfully registered!", {
          description: "We've sent a confirmation to your email.",
        });
        fetchEventData(); // Refresh to get updated count
      } else {
        toast.error(response.message || "Registration failed");
      }
    } catch (error) {
      toast.error("An error occurred during registration");
    } finally {
      setActionLoading(false);
    }
  };

  const handleWishlist = async () => {
    if (!user) {
      navigate("/login");
      return;
    }

    setWishlistLoading(true);
    try {
      if (isWishlisted) {
        const res = await api.delete(`/wishlist/remove?eventId=${id}`, token || undefined);
        if (res.success) {
          setIsWishlisted(false);
          toast.success("Removed from wishlist");
        }
      } else {
        const res = await api.post("/wishlist/add", { eventId: id }, token || undefined);
        if (res.success) {
          setIsWishlisted(true);
          toast.success("Added to wishlist");
        }
      }
    } catch (error) {
      toast.error("Wishlist update failed");
    } finally {
      setWishlistLoading(false);
    }
  };

  const handleShare = async (platform?: string) => {
    const shareUrl = window.location.href;
    const shareTitle = `Join me at ${event.title}!`;
    const shareText = `${event.description?.substring(0, 100)}... Check it out on Eventra!`;

    if (!platform && navigator.share) {
      try {
        await navigator.share({
          title: shareTitle,
          text: shareText,
          url: shareUrl,
        });
        return;
      } catch (err) {
        console.error("Share failed:", err);
      }
    }

    switch (platform) {
      case "whatsapp":
        window.open(`https://wa.me/?text=${encodeURIComponent(shareTitle + " " + shareUrl)}`, "_blank");
        break;
      case "twitter":
        window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(shareTitle)}&url=${encodeURIComponent(shareUrl)}`, "_blank");
        break;
      case "linkedin":
        window.open(`https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(shareUrl)}`, "_blank");
        break;
      default:
        navigator.clipboard.writeText(shareUrl);
        toast.success("Link copied to clipboard!");
    }
  };

  const relatedEvents = allEvents.filter((e) => e.category === event.category && (e.id || e._id) !== (event.id || event._id)).slice(0, 3);
  const displayImage = event.imageUrl || event.image || "https://images.unsplash.com/photo-1501281668745-f7f57925c3b4?w=1200&h=800&fit=crop";
  const organizerDisplay = event.organizerName || event.organizer || "Campus Admin";

  return (
    <div className="min-h-screen bg-background">
      <nav className="sticky top-0 z-50 glass border-b border-border/50">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between">
          <Link to="/student/explore" className="flex items-center gap-2.5 px-4 py-2 rounded-xl text-sm text-muted-foreground hover:text-primary hover:bg-primary/5 transition-all font-bold group">
            <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" /> Back to Explore
          </Link>
          <div className="hidden sm:flex items-center gap-2">
            <h2 className="text-xs font-black uppercase tracking-widest text-muted-foreground opacity-50">Event Details</h2>
          </div>
          <div className="w-24" /> {/* Spacer */}
        </div>
      </nav>

      <div className="max-w-6xl mx-auto px-4 sm:px-6 py-8">
        <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }}>
          {/* Hero image */}
          <div className="rounded-3xl overflow-hidden shadow-2xl mb-12 relative group">
            <img src={displayImage} alt={event.title} className="w-full h-[400px] lg:h-[500px] object-cover transition-transform duration-1000 group-hover:scale-105" />
            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent" />
            <div className="absolute bottom-8 left-8 right-8">
              <span className={`${categoryColors[typeof event.category === 'string' ? event.category : event.category?.name] || "bg-primary text-white"} px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest inline-block mb-4 shadow-lg`}>
                {typeof event.category === 'string' ? event.category : event.category?.name || "Event"}
              </span>
              <h1 className="text-3xl sm:text-4xl lg:text-5xl font-black text-white leading-tight tracking-tighter drop-shadow-sm">{event.title}</h1>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            {/* Main content */}
            <div className="lg:col-span-2 space-y-10">
              {/* Quick info */}
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                {[
                  { icon: Calendar, label: "Date", value: event.date },
                  { icon: Clock, label: "Time", value: event.time },
                  { icon: MapPin, label: "Venue", value: event.venue },
                  { icon: User, label: "Organizer", value: organizerDisplay },
                ].map((item, idx) => (
                  <motion.div
                    key={item.label}
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ delay: 0.1 * idx }}
                    className="bg-card rounded-2xl border border-border/50 p-5 hover:border-primary/30 transition-all hover:bg-muted/30"
                  >
                    <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center text-primary mb-3">
                       <item.icon className="w-4 h-4" />
                    </div>
                    <label className="text-[10px] font-black text-muted-foreground uppercase tracking-wider mb-1 block opacity-60">{item.label}</label>
                    <p className="text-sm font-bold text-foreground truncate">{item.value}</p>
                  </motion.div>
                ))}
              </div>

              {/* Action Buttons Horizontal */}
              <div className="flex flex-wrap items-center gap-4 py-6 border-y border-border/50">
                 <button 
                   onClick={handleRegister}
                   disabled={actionLoading || registered || event.status !== "open" || spotsLeft <= 0}
                   className={`flex-1 min-w-[200px] h-14 rounded-2xl font-black text-sm uppercase tracking-widest transition-all active:scale-95 flex items-center justify-center gap-3 shadow-xl ${
                    registered 
                      ? "bg-green-500/10 text-green-500 border border-green-500/20 cursor-default"
                      : "bg-primary text-white hover:bg-primary/90 shadow-primary/20"
                   }`}
                 >
                    {actionLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : registered ? <CheckCircle2 className="w-5 h-5" /> : null}
                    {registered ? "Registered" : "Register Now"}
                 </button>

                 <button 
                   onClick={handleWishlist}
                   disabled={wishlistLoading}
                   className={`h-14 px-8 rounded-2xl font-black text-sm uppercase tracking-widest transition-all active:scale-95 flex items-center justify-center gap-3 border-2 ${
                    isWishlisted 
                      ? "bg-accent/10 border-accent/20 text-accent"
                      : "bg-card border-border hover:border-accent hover:text-accent"
                   }`}
                 >
                    {wishlistLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Heart className={`w-5 h-5 ${isWishlisted ? "fill-current" : ""}`} />}
                    {isWishlisted ? "Saved" : "Wishlist"}
                 </button>

                 <div className="flex items-center gap-2">
                    <button 
                      onClick={() => handleShare()}
                      className="w-14 h-14 rounded-2xl bg-card border border-border flex items-center justify-center text-muted-foreground hover:text-primary hover:border-primary transition-all active:scale-95"
                    >
                       <Share2 className="w-5 h-5" />
                    </button>
                    {/* Social quick links */}
                    <div className="flex gap-2">
                       {['whatsapp', 'twitter', 'linkedin'].map(p => (
                         <button 
                           key={p} 
                           onClick={() => handleShare(p)}
                           className="w-10 h-10 rounded-xl bg-muted flex items-center justify-center text-muted-foreground hover:text-primary transition-all hover:bg-primary/5"
                         >
                            <span className="sr-only">Share on {p}</span>
                            <div className="w-4 h-4 bg-muted-foreground/20 rounded-full" /> {/* Placeholder for social icons */}
                         </button>
                       ))}
                    </div>
                 </div>
              </div>

              {/* Description */}
              <div className="space-y-4">
                <h2 className="font-black text-foreground text-2xl tracking-tighter">About this event</h2>
                <div className="prose prose-sm max-w-none text-muted-foreground leading-relaxed text-base">
                  {event.description}
                </div>
              </div>

              {/* Event Discussion / Comments Section */}
              <div className="mt-12 pt-10 border-t border-border/50">
                <h2 className="text-2xl font-black text-foreground tracking-tighter flex items-center gap-3 mb-8">
                  <MessageSquare className="w-6 h-6 text-primary" /> Event Discussion
                </h2>

                {user ? (
                  <form onSubmit={handleCommentSubmit} className="mb-10 relative">
                    <textarea
                      value={newComment}
                      onChange={(e) => setNewComment(e.target.value)}
                      placeholder="Ask a question or share your thoughts..."
                      className="w-full bg-muted/30 border border-border/50 rounded-2xl p-5 pr-16 resize-none focus:outline-none focus:ring-2 focus:ring-primary/50 text-sm font-medium transition-all"
                      rows={3}
                    />
                    <button 
                      type="submit"
                      disabled={commentLoading || !newComment.trim()}
                      className="absolute bottom-5 right-5 p-2 bg-primary text-white rounded-xl hover:bg-primary/90 disabled:opacity-50 transition-all active:scale-95"
                    >
                      {commentLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                    </button>
                  </form>
                ) : (
                  <div className="mb-10 p-6 bg-muted/30 border border-border/50 rounded-2xl text-center">
                    <p className="text-sm font-bold text-muted-foreground mb-4">You must be registered to participate in the discussion.</p>
                    <Link to="/login" className="text-primary text-xs font-black uppercase tracking-widest hover:underline">Log in to comment</Link>
                  </div>
                )}

                <div className="space-y-6">
                  {comments.length > 0 ? comments.map((comment) => (
                    <motion.div 
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      key={comment.id} 
                      className="flex gap-4 p-5 bg-card border border-border/50 rounded-2xl shadow-sm"
                    >
                      <div className="w-10 h-10 rounded-full bg-gradient-to-br from-primary/20 to-indigo-600/20 text-primary flex items-center justify-center font-black text-sm shrink-0 overflow-hidden">
                        {comment.userPicture ? <img src={comment.userPicture} alt="" className="w-full h-full object-cover" /> : (comment.userName?.charAt(0) || 'U')}
                      </div>
                      <div className="flex-1">
                        <div className="flex items-center justify-between mb-1">
                          <h4 className="font-bold text-sm text-foreground">{comment.userName}</h4>
                          <span className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold">
                            {new Date(comment.createdAt).toLocaleDateString()}
                          </span>
                        </div>
                        <p className="text-sm text-muted-foreground leading-relaxed">{comment.text}</p>
                      </div>
                    </motion.div>
                  )) : (
                    <div className="text-center py-8 text-muted-foreground text-sm font-medium">
                      No comments yet. Be the first to start the discussion!
                    </div>
                  )}
                </div>
              </div>

              {/* Participants for Organizers/Admins */}
              {(user?.role === 'admin' || user?.id === event.organizerId) && (
                <div className="mt-12 bg-card rounded-3xl border border-border/50 overflow-hidden">
                  <div className="p-8 border-b border-border/50 flex items-center justify-between bg-muted/30">
                    <div>
                      <h2 className="font-black text-xl text-foreground tracking-tight">Registered Participants</h2>
                      <p className="text-sm text-muted-foreground mt-1">Full list of attendees and registration details.</p>
                    </div>
                    <div className="bg-primary/10 px-4 py-2 rounded-xl border border-primary/20 font-black text-primary text-sm">
                      {participants.length} TOTAL
                    </div>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-left">
                      <thead>
                        <tr className="bg-muted/20 border-b border-border/50 text-[10px] font-black uppercase tracking-widest text-muted-foreground">
                          <th className="px-8 py-4">Participant</th>
                          <th className="px-8 py-4">Status</th>
                          <th className="px-8 py-4">Registered Date</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-border/50">
                        {participants.length > 0 ? participants.map((p: any) => (
                          <tr key={p.userId} className="hover:bg-muted/40 transition-colors">
                            <td className="px-8 py-5">
                              <div className="flex items-center gap-3">
                                <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-primary/20 to-indigo-600/20 flex items-center justify-center text-primary font-black text-xs">
                                  {p.studentName?.charAt(0)}
                                </div>
                                <div>
                                  <p className="text-sm font-bold text-foreground">{p.studentName}</p>
                                  <p className="text-[10px] text-muted-foreground">{p.studentEmail}</p>
                                </div>
                              </div>
                            </td>
                            <td className="px-8 py-5">
                               <span className="px-2.5 py-1 rounded-full bg-green-500/10 text-green-500 text-[10px] font-black uppercase tracking-tighter">
                                 Confirmed
                               </span>
                            </td>
                            <td className="px-8 py-5 text-xs text-muted-foreground">
                              {new Date(p.registrationDate).toLocaleDateString()}
                            </td>
                          </tr>
                        )) : (
                          <tr>
                            <td colSpan={3} className="px-8 py-12 text-center text-muted-foreground">No participants registered yet.</td>
                          </tr>
                        )}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
            </div>

            {/* Sidebar */}
            <div className="space-y-6">
              {/* Registration card */}
              <motion.div
                initial={{ opacity: 0, y: 12 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3 }}
                className="bg-card rounded-3xl shadow-xl shadow-foreground/5 border border-border/50 p-8 sticky top-24"
              >
                <div className="flex items-center justify-between mb-8">
                  <div className="flex flex-col">
                     <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest mb-1">Status</span>
                     <div className={`flex items-center gap-2 text-sm font-black uppercase tracking-tight ${
                       event.status === "completed" ? "text-muted-foreground" :
                       event.status === "closed" || spotsLeft <= 0 ? "text-destructive" :
                       "text-accent"
                     }`}>
                       <div className={`w-2 h-2 rounded-full animate-pulse ${
                         event.status === "completed" ? "bg-muted-foreground" :
                         event.status === "closed" || spotsLeft <= 0 ? "bg-destructive" :
                         "bg-accent"
                       }`} />
                       {event.status === "completed" ? "Completed" : event.status === "closed" || spotsLeft <= 0 ? "Closed" : "Live"}
                     </div>
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest mb-1 block">Pricing</span>
                    <div className={`text-2xl font-black tracking-tighter ${event.isPaidEvent ? "text-primary" : "text-green-500"}`}>
                       {event.isPaidEvent ? `Γé╣${event.price}` : "FREE"}
                    </div>
                  </div>
                </div>
                
                <div className="space-y-4 mb-8">
                  <div className="flex justify-between items-end">
                    <div className="flex flex-col">
                       <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Attendance</span>
                       <span className="text-xl font-black text-foreground tracking-tighter tabular-nums mt-1">{currentRegistered}</span>
                    </div>
                    <span className="text-xs font-black text-muted-foreground opacity-40">/ {event.maxParticipants} CAP</span>
                  </div>
                  <div className="h-3 bg-muted rounded-full overflow-hidden p-0.5">
                    <motion.div
                      initial={{ width: 0 }}
                      animate={{ width: `${capacityPercent}%` }}
                      transition={{ duration: 1.5, ease: "circOut" }}
                      className={`h-full rounded-full shadow-inner ${capacityPercent >= 90 ? "bg-destructive" : "bg-gradient-to-r from-primary to-indigo-600"}`}
                    />
                  </div>
                  <div className="flex justify-between items-center bg-muted/40 p-3 rounded-2xl">
                    <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">{spotsLeft} Vacancies Left</span>
                    {spotsLeft <= 5 && spotsLeft > 0 && <span className="text-[10px] font-black text-destructive uppercase animate-bounce">Filling Fast!</span>}
                  </div>
                </div>
                
                <div className="p-4 bg-muted/40 rounded-2xl border border-border/50 text-center mb-6">
                   <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest mb-2">Event Countdown</p>
                   <div className="flex justify-center gap-3">
                      {[{v: countdown.days, l:'D'}, {v: countdown.hours, l:'H'}, {v: countdown.minutes, l:'M'}, {v: countdown.seconds, l:'S'}].map(c => (
                        <div key={c.l} className="flex flex-col">
                           <span className="text-lg font-black text-primary tabular-nums tracking-tighter leading-none">{String(c.v).padStart(2,'0')}</span>
                           <span className="text-[8px] font-black text-muted-foreground/60">{c.l}</span>
                        </div>
                      ))}
                   </div>
                </div>

                <p className="text-[10px] text-center text-muted-foreground leading-relaxed italic border-t border-border/50 pt-4 opacity-50 font-bold">
                  By registering, you agree to the event guidelines and safety protocols.
                </p>
              </motion.div>
            </div>
          </div>
        </motion.div>
      </div>
    </div>
  );
};

export default EventDetails;

import { useState, useMemo, useRef, useEffect, useCallback } from "react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import EventCard from "@/components/EventCard";
import { Search, SlidersHorizontal, X, Loader2 } from "lucide-react";
import { toast } from "sonner";
import { AnimatePresence, motion } from "framer-motion";
import { useSearchParams } from "react-router-dom";
import { api } from "@/lib/api";

const ExploreEvents = () => {
  const [searchParams] = useSearchParams();
  const initialSearch = searchParams.get("q") || "";
  
  const [search, setSearch] = useState(initialSearch);
  const [category, setCategory] = useState("All");
  const [location, setLocation] = useState("All");
  const [dateFilter, setDateFilter] = useState("");
  const [feeType, setFeeType] = useState("All");
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [events, setEvents] = useState<any[]>([]);
  const [categories, setCategories] = useState<any[]>(["All"]);
  const [loading, setLoading] = useState(true);
  const searchRef = useRef<HTMLDivElement>(null);

  // Fetch categories
  useEffect(() => {
    const fetchCats = async () => {
      try {
        const response = await api.get("/categories");
        if (response.success) {
          setCategories(["All", ...response.data.map((c: any) => c.name)]);
        }
      } catch (e) {
        console.error("Failed to fetch categories");
      }
    };
    fetchCats();
  }, []);

  // Debounced fetch - only fires 400ms after user stops typing
  const fetchEvents = useCallback(async () => {
    setLoading(true);
    try {
      const query = new URLSearchParams();
      if (search) query.append("search", search);
      if (category !== "All") query.append("category", category);
      
      const response = await api.get(`/events?${query.toString()}`);
      if (response.success) {
        setEvents(response.data);
      } else {
        toast.error("Failed to load events");
      }
    } catch (error) {
      toast.error("Failed to connect to server");
    } finally {
      setLoading(false);
    }
  }, [search, category]);

  useEffect(() => {
    // Debounce the API call by 400ms
    const timer = setTimeout(() => {
      fetchEvents();
    }, 400);
    return () => clearTimeout(timer);
  }, [fetchEvents]);

  // Update search if URL param changes
  useEffect(() => {
    if (initialSearch) {
      setSearch(initialSearch);
    }
  }, [initialSearch]);

  const locations = useMemo(() => ["All", ...Array.from(new Set(events.map(e => e.venue)))], [events]);

  const suggestions = useMemo(() => {
    if (!search || search.length < 2) return [];
    return events
      .filter((e) => {
        const catStr = typeof e.category === 'string' ? e.category : e.category?.name || "";
        return e.title.toLowerCase().includes(search.toLowerCase()) || catStr.toLowerCase().includes(search.toLowerCase());
      })
      .slice(0, 5);
  }, [search, events]);

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const filtered = events.filter((e) => {
    // Basic search is already handled by API for title, but we keep some client-side refinement for venue/date
    const matchLoc = location === "All" || e.venue === location;
    const matchDate = !dateFilter || e.date === dateFilter;
    const matchFee = feeType === "All" 
      ? true 
      : feeType === "Free" ? !e.isPaidEvent 
      : e.isPaidEvent;
    return matchLoc && matchDate && matchFee;
  });

  return (
    <DashboardLayout role="student">
      <div className="mb-8 items-center justify-between flex">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Explore Events</h1>
          <p className="text-sm text-muted-foreground mt-1">Discover what's happening on campus ΓÇö {events.length} events available.</p>
        </div>
      </div>

      <div className="bg-card p-4 rounded-xl shadow-surface mb-8 border border-border">
        <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
          
          {/* Search */}
          <div className="relative" ref={searchRef}>
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <input
              type="text"
              placeholder="Search events..."
              value={search}
              onChange={(e) => { setSearch(e.target.value); setShowSuggestions(true); }}
              onFocus={() => setShowSuggestions(true)}
              className="w-full pl-10 pr-10 py-2.5 bg-muted/40 border border-input rounded-xl text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all"
            />
            {search && (
              <button onClick={() => { setSearch(""); setShowSuggestions(false); }} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                <X className="w-4 h-4" />
              </button>
            )}
            <AnimatePresence>
              {showSuggestions && suggestions.length > 0 && (
                <motion.div
                  initial={{ opacity: 0, y: -4 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -4 }}
                  className="absolute top-full left-0 right-0 mt-1.5 bg-card border border-border rounded-xl shadow-surface-elevated overflow-hidden z-50"
                >
                  {suggestions.map((event) => {
                    const catName = typeof event.category === 'string' ? event.category : event.category?.name || "";
                    const eventId = event.id || event._id;
                    return (
                    <button key={eventId} onClick={() => { setSearch(event.title); setShowSuggestions(false); }} className="w-full text-left px-4 py-3 hover:bg-muted/50 transition-colors flex items-center gap-3 border-b border-border last:border-0">
                      <div className="w-8 h-8 rounded-md bg-primary/10 flex items-center justify-center text-primary text-xs font-black shrink-0">
                        {event.title?.charAt(0)}
                      </div>
                      <div>
                        <p className="text-sm font-medium text-card-foreground line-clamp-1">{event.title}</p>
                        <p className="text-[10px] text-muted-foreground">{catName}</p>
                      </div>
                    </button>
                    );
                  })}
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Category Dropdown */}
          <div className="relative">
            <select
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              className="w-full px-4 py-2.5 bg-muted/40 border border-input rounded-xl text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 appearance-none transition-all cursor-pointer"
            >
              {categories.map((cat) => {
                const name = typeof cat === 'string' ? cat : cat.name;
                return (
                  <option key={name} value={name}>
                    {name === "All" ? "All Categories" : name}
                  </option>
                );
              })}
            </select>
          </div>

          {/* Location Dropdown */}
          <div className="relative">
             <select
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              className="w-full px-4 py-2.5 bg-muted/40 border border-input rounded-xl text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 appearance-none transition-all cursor-pointer"
            >
              <option value="All">All Locations</option>
              {locations.filter(l => l !== "All").map((loc) => <option key={loc} value={loc}>{loc}</option>)}
            </select>
          </div>

          {/* Date Filter */}
          <div className="relative">
            <input
              type="date"
              value={dateFilter}
              onChange={(e) => setDateFilter(e.target.value)}
              className="w-full px-4 py-2.5 bg-muted/40 border border-input rounded-xl text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all cursor-pointer min-h-[42px]"
            />
          </div>

          {/* Free/Paid Dropdown */}
          <div className="relative">
             <select
              value={feeType}
              onChange={(e) => setFeeType(e.target.value)}
              className="w-full px-4 py-2.5 bg-muted/40 border border-input rounded-xl text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 appearance-none transition-all cursor-pointer"
            >
              <option value="All">All Prices</option>
              <option value="Free">Free</option>
              <option value="Paid">Paid</option>
            </select>
          </div>

        </div>
        
        {/* Active Filters Reset */}
        {(search || category !== "All" || location !== "All" || dateFilter || feeType !== "All") && (
          <div className="mt-4 flex items-center gap-2 pt-4 border-t border-border/50">
            <span className="text-xs text-muted-foreground font-medium">Active Filters:</span>
            <button
              onClick={() => { setSearch(""); setCategory("All"); setLocation("All"); setDateFilter(""); setFeeType("All"); }}
              className="text-xs text-primary hover:text-primary/80 font-medium transition-colors"
            >
              Clear All
            </button>
          </div>
        )}
      </div>

      <p className="text-xs text-muted-foreground mb-4">{filtered.length} event{filtered.length !== 1 ? "s" : ""} found</p>

      <AnimatePresence mode="wait">
        {loading ? (
          <motion.div
            key="loading"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="flex flex-col items-center justify-center py-20"
          >
            <Loader2 className="w-10 h-10 text-primary animate-spin mb-4" />
            <p className="text-muted-foreground animate-pulse">Loading events...</p>
          </motion.div>
        ) : filtered.length === 0 ? (
          <motion.div
            key="empty"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="text-center py-20"
          >
            <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center mx-auto mb-4">
              <Search className="w-6 h-6 text-muted-foreground" />
            </div>
            <p className="text-muted-foreground font-medium">No events found</p>
            <p className="text-sm text-muted-foreground mt-1">Try adjusting your filters or check back later.</p>
          </motion.div>
        ) : (
          <motion.div
            key="grid"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="space-y-12"
          >
            {/* Upcoming / Ongoing Events */}
            {filtered.filter(e => e.status !== "completed").length > 0 && (
              <section>
                <h2 className="text-xl font-bold text-foreground mb-6">Upcoming Events</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                  {filtered.filter(e => e.status !== "completed").map((event, i) => (
                    <EventCard
                      key={event.id || event._id}
                      event={event}
                      index={i}
                      onRegister={() => toast.success(`Successfully registered for "${event.title}"`, { description: "We've sent a confirmation to your student email." })}
                    />
                  ))}
                </div>
              </section>
            )}

            {/* Past Events */}
            {filtered.filter(e => e.status === "completed").length > 0 && (
              <section>
                <div className="flex items-center gap-4 mb-6 pt-6 border-t border-border">
                  <h2 className="text-xl font-bold text-muted-foreground">Past Events</h2>
                  <span className="bg-muted text-muted-foreground px-2.5 py-1 rounded-md text-[11px] font-bold uppercase tracking-wider">
                    Completed
                  </span>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6 opacity-75 grayscale-[0.3]">
                  {filtered.filter(e => e.status === "completed").map((event, i) => (
                    <EventCard
                      key={event.id || event._id}
                      event={event}
                      index={i}
                    />
                  ))}
                </div>
              </section>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </DashboardLayout>
  );
};

export default ExploreEvents;

import DashboardLayout from "@/components/layout/DashboardLayout";
import { toast } from "sonner";
import { motion } from "framer-motion";
import { CalendarCheck, Search, Loader2 } from "lucide-react";
import { useState, useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { api } from "@/lib/api";
import { QRCodeSVG } from "qrcode.react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";

const MyRegistrations = () => {
  const { user, token } = useAuth();
  const [registrations, setRegistrations] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [qrModalOpen, setQrModalOpen] = useState(false);
  const [selectedReg, setSelectedReg] = useState<any>(null);

  const fetchRegistrations = async () => {
    if (!user?.id) return;
    setLoading(true);
    try {
      const response = await api.get(`/registrations/user/${user.id}`, token || undefined);
      if (response.success) {
        setRegistrations(response.data);
      }
    } catch (error) {
      toast.error("Failed to load registrations");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRegistrations();
  }, [user?.id, token]);

  const handleCancel = async (regId: string, eventName: string) => {
    try {
      const response = await api.delete(`/registrations/${regId}`, token || undefined);
      if (response.success) {
        toast.success(`Cancelled registration for "${eventName}"`);
        fetchRegistrations();
      } else {
        toast.error(response.message || "Failed to cancel");
      }
    } catch (error) {
      toast.error("Error cancelling registration");
    }
  };

  const filtered = registrations.filter((r) =>
    r.eventName?.toLowerCase().includes(search.toLowerCase()) || 
    r.event?.title?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <DashboardLayout role="student">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-foreground">My Registrations</h1>
        <p className="text-sm text-muted-foreground mt-1">Track all your event registrations ΓÇö {registrations.length} total.</p>
      </div>

      <div className="mb-6">
        <div className="relative max-w-md">
          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <input
            type="text"
            placeholder="Search your registrations..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 bg-card border border-input rounded-xl text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring shadow-surface"
          />
        </div>
      </div>

      {loading ? (
        <div className="py-20 flex flex-col items-center">
          <Loader2 className="w-8 h-8 text-primary animate-spin mb-4" />
          <p className="text-muted-foreground animate-pulse">Loading your registrations...</p>
        </div>
      ) : (
        <motion.div
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-card rounded-xl shadow-surface overflow-hidden"
        >
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-border bg-muted/50">
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Event Name</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Event Date</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Registration Date</th>
                  <th className="text-left py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Status</th>
                  <th className="text-right py-3.5 px-5 font-semibold text-muted-foreground text-xs uppercase tracking-wider">Action</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((reg, i) => (
                  <motion.tr
                    key={reg.id}
                    initial={{ opacity: 0, x: -10 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: i * 0.05 }}
                    className="border-b border-border last:border-0 hover:bg-muted/30 transition-colors group"
                  >
                    <td className="py-4 px-5">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-lg bg-primary/10 text-primary flex items-center justify-center shrink-0">
                          <CalendarCheck className="w-4 h-4" />
                        </div>
                        <span className="font-medium text-card-foreground group-hover:text-primary transition-colors">{reg.event?.title || reg.eventName}</span>
                      </div>
                    </td>
                    <td className="py-4 px-5 text-muted-foreground tabular-nums">{reg.event?.date || "N/A"}</td>
                    <td className="py-4 px-5 text-muted-foreground tabular-nums">{new Date(reg.registeredAt).toLocaleDateString()}</td>
                    <td className="py-4 px-5">
                      <span className={`px-2.5 py-1 rounded-md text-[11px] font-bold uppercase tracking-wider ${
                        reg.status === "registered" || reg.status === "confirmed" ? "bg-accent/10 text-accent" :
                        reg.status === "cancelled" ? "bg-destructive/10 text-destructive" :
                        "bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300"
                      }`}>
                        {reg.status}
                      </span>
                    </td>
                    <td className="py-4 px-5 text-right">
                      <div className="flex items-center justify-end gap-3">
                        <button
                          onClick={() => { setSelectedReg(reg); setQrModalOpen(true); }}
                          className="text-xs text-primary font-bold hover:underline"
                        >
                          View QR
                        </button>
                        {reg.status !== "cancelled" && (
                          <button
                            onClick={() => handleCancel(reg.id, reg.event?.title || reg.eventName)}
                            className="text-xs text-destructive hover:underline font-semibold"
                          >
                            Cancel
                          </button>
                        )}
                      </div>
                    </td>
                  </motion.tr>
                ))}
              </tbody>
            </table>
          </div>
          {filtered.length === 0 && (
            <div className="py-12 text-center text-muted-foreground text-sm">No registrations found.</div>
          )}
        </motion.div>
      )}

      {/* QR Code Modal */}
      <Dialog open={qrModalOpen} onOpenChange={setQrModalOpen}>
        <DialogContent className="max-w-xs sm:max-w-sm flex flex-col items-center text-center p-6">
          <DialogHeader>
            <DialogTitle className="text-xl font-black mb-2">Event Ticket</DialogTitle>
          </DialogHeader>
          <div className="bg-white p-4 rounded-xl shadow-inner mb-4 inline-block">
            {selectedReg && (
              <QRCodeSVG 
                value={selectedReg.id} 
                size={200}
                level="H"
                includeMargin={true}
              />
            )}
          </div>
          <p className="text-sm font-bold text-foreground">
            {selectedReg?.event?.title || selectedReg?.eventName}
          </p>
          <p className="text-xs text-muted-foreground mt-1">
            Ticket ID: {selectedReg?.ticketNumber || selectedReg?.id}
          </p>
          <p className="text-xs text-muted-foreground mt-2 px-4">
            Show this QR code at the venue for quick check-in.
          </p>
        </DialogContent>
      </Dialog>
    </DashboardLayout>
  );
};

export default MyRegistrations;

import { useState, useEffect } from "react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { motion, AnimatePresence } from "framer-motion";
import { 
  User as UserIcon, Mail, Shield, ShieldCheck, CheckCircle, 
  Loader2, Calendar, MapPin, XCircle, Heart, Settings as SettingsIcon,
  LogOut, Clock, ExternalLink, Trash2
} from "lucide-react";
import { useAuth } from "@/context/AuthContext";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Link } from "react-router-dom";

const Profile = () => {
  const { user, token, logout } = useAuth();
  const [activeSection, setActiveSection] = useState("overview");
  const [registrations, setRegistrations] = useState<any[]>([]);
  const [wishlist, setWishlist] = useState<any[]>([]);
  const [tickets, setTickets] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const fetchUserData = async () => {
    if (!user?.id) return;
    setLoading(true);
    try {
      const [regsRes, wishRes, ticketsRes] = await Promise.all([
        api.get(`/registrations/user/${user.id}`, token || undefined),
        api.get(`/wishlist/user/${user.id}`, token || undefined),
        api.get(`/tickets/user/${user.id}`, token || undefined)
      ]);

      if (regsRes.success) setRegistrations(regsRes.data);
      if (wishRes.success) setWishlist(wishRes.data);
      if (ticketsRes.success) setTickets(ticketsRes.data);
    } catch (error) {
      toast.error("Failed to fetch user data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUserData();
  }, [user?.id, token]);

  const handleCancelRegistration = async (regId: string) => {
    setActionLoading(regId);
    try {
      const res = await api.delete(`/registrations/${regId}`, token || undefined);
      if (res.success) {
        toast.success("Registration cancelled");
        fetchUserData();
      }
    } catch (error) {
      toast.error("Cancellation failed");
    } finally {
      setActionLoading(null);
    }
  };

  const handleRemoveFromWishlist = async (eventId: string) => {
    setActionLoading(eventId);
    try {
      const res = await api.delete(`/wishlist/remove?eventId=${eventId}`, token || undefined);
      if (res.success) {
        toast.success("Removed from wishlist");
        fetchUserData();
      }
    } catch (error) {
      toast.error("Wishlist removal failed");
    } finally {
      setActionLoading(null);
    }
  };

  if (!user) return null;

  const sections = [
    { id: "overview", label: "Overview", icon: UserIcon },
    { id: "registrations", label: "My Registrations", icon: Calendar },
    { id: "wishlist", label: "Saved Events", icon: Heart },
    { id: "tickets", label: "Event Tickets", icon: CheckCircle },
    { id: "settings", label: "Settings", icon: SettingsIcon },
  ];

  const profileOverview = [
    { icon: UserIcon, label: "Full Name", value: user.name },
    { icon: Mail, label: "Email Address", value: user.email },
    { icon: Shield, label: "Account Role", value: user.role.toUpperCase() },
    { icon: Clock, label: "Member Since", value: new Date(user.createdAt || Date.now()).toLocaleDateString() },
  ];

  return (
    <DashboardLayout role={user.role}>
      <div className="max-w-6xl mx-auto py-8 px-4">
        <header className="mb-12">
           <h1 className="text-4xl font-black text-foreground tracking-tighter mb-2 italic">Student Profile</h1>
           <p className="text-muted-foreground font-medium">Manage your personal information and campus activities.</p>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Tabs Sidebar */}
          <div className="space-y-2">
            {sections.map((s) => (
              <button
                key={s.id}
                onClick={() => setActiveSection(s.id)}
                className={`w-full flex items-center gap-3 px-5 py-4 rounded-2xl text-sm font-black transition-all ${
                  activeSection === s.id 
                    ? "bg-primary text-white shadow-lg shadow-primary/20 translate-x-1" 
                    : "bg-card hover:bg-muted text-muted-foreground"
                }`}
              >
                <s.icon className="w-5 h-5" />
                {s.label}
              </button>
            ))}
            <button 
              onClick={logout}
              className="w-full flex items-center gap-3 px-5 py-4 rounded-2xl text-sm font-black text-destructive hover:bg-destructive/5 transition-all mt-8"
            >
              <LogOut className="w-5 h-5" />
              Sign Out
            </button>
          </div>

          {/* Main Content Area */}
          <div className="lg:col-span-3 min-h-[500px]">
            <AnimatePresence mode="wait">
              {activeSection === "overview" && (
                <motion.div
                  key="overview"
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  className="space-y-6"
                >
                  <div className="bg-card rounded-3xl border border-border/50 p-8 shadow-xl shadow-foreground/5 relative overflow-hidden">
                    <div className="flex items-center gap-10">
                      <div className="w-32 h-32 rounded-3xl bg-gradient-to-br from-primary to-indigo-600 border-4 border-card shadow-2xl flex items-center justify-center text-4xl font-black text-white shrink-0 relative group cursor-pointer overflow-hidden">
                        {user.picture ? <img src={user.picture} alt={user.name} className="w-full h-full object-cover group-hover:opacity-50 transition-opacity" /> : <span className="group-hover:opacity-50 transition-opacity">{user.name.charAt(0)}</span>}
                        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/40 backdrop-blur-sm">
                          <span className="text-xs tracking-widest uppercase">Upload</span>
                        </div>
                      </div>
                      <div className="flex-1 min-w-0">
                        <h2 className="text-3xl font-black text-foreground tracking-tighter mb-1">{user.name}</h2>
                        <p className="text-muted-foreground font-medium mb-4 opacity-70 italic">{user.email}</p>
                        <div className="flex gap-2">
                          <span className="px-4 py-1.5 rounded-full bg-primary/10 text-primary border border-primary/20 text-[10px] font-black uppercase tracking-widest">
                            {user.role}
                          </span>
                          <span className="px-4 py-1.5 rounded-full bg-green-500/10 text-green-500 border border-green-500/20 text-[10px] font-black uppercase tracking-widest">
                            Verified Account
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>

                  <form 
                    onSubmit={async (e) => {
                      e.preventDefault();
                      setActionLoading('update-profile');
                      const formData = new FormData(e.currentTarget);
                      const data = {
                        name: formData.get('name'),
                        department: formData.get('department'),
                      };
                      try {
                        const res = await api.put('/users/update-profile', data, token || undefined);
                        if (res.success) {
                          toast.success("Profile updated successfully");
                          // You would typically update local auth state here as well
                        } else {
                          toast.error(res.message || "Failed to update profile");
                        }
                      } catch (error) {
                        toast.error("An error occurred");
                      } finally {
                        setActionLoading(null);
                      }
                    }}
                    className="bg-card rounded-3xl border border-border/50 p-8 shadow-xl shadow-foreground/5 grid grid-cols-1 md:grid-cols-2 gap-8"
                  >
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block opacity-60">Full Name</label>
                        <input name="name" defaultValue={user.name} className="w-full bg-muted/30 border border-border/50 rounded-xl px-4 py-3 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all" />
                     </div>
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block opacity-60">Email Address</label>
                        <input name="email" defaultValue={user.email} disabled className="w-full bg-muted/10 border border-border/10 rounded-xl px-4 py-3 text-sm font-bold text-muted-foreground cursor-not-allowed" />
                     </div>
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block opacity-60">Department</label>
                        <input name="department" defaultValue={user.department || ''} placeholder="e.g. Computer Science" className="w-full bg-muted/30 border border-border/50 rounded-xl px-4 py-3 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all" />
                     </div>
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block opacity-60">Member Since</label>
                        <input readOnly value={new Date(user.createdAt || Date.now()).toLocaleDateString()} className="w-full bg-muted/10 border border-border/10 rounded-xl px-4 py-3 text-sm font-bold text-muted-foreground cursor-not-allowed" />
                     </div>
                     
                     <div className="col-span-1 md:col-span-2 pt-4 flex justify-end">
                        <button 
                          type="submit" 
                          disabled={actionLoading === 'update-profile'}
                          className="px-8 py-3.5 rounded-2xl bg-primary text-white font-black text-xs uppercase tracking-widest hover:bg-primary/90 transition-all shadow-lg shadow-primary/20 flex items-center gap-2"
                        >
                          {actionLoading === 'update-profile' && <Loader2 className="w-4 h-4 animate-spin" />}
                          Save Changes
                        </button>
                     </div>
                  </form>
                </motion.div>
              )}

              {activeSection === "registrations" && (
                <motion.div
                  key="registrations"
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  className="space-y-6"
                >
                  <div className="flex items-center justify-between mb-2">
                    <h2 className="text-2xl font-black text-foreground tracking-tighter">My Active Registrations</h2>
                    <span className="bg-primary/10 px-3 py-1 rounded-lg text-primary text-[10px] font-black uppercase tracking-widest">{registrations.length} Total</span>
                  </div>

                  <div className="grid grid-cols-1 gap-4">
                    {registrations.length > 0 ? registrations.map((r: any) => (
                      <div key={r.id} className="bg-card rounded-3xl border border-border/50 p-6 flex flex-col md:flex-row items-center justify-between gap-6 hover:border-primary/30 transition-all group">
                         <div className="flex items-center gap-5 w-full md:w-auto">
                            <div className="w-14 h-14 rounded-2xl bg-muted flex items-center justify-center text-muted-foreground flex-shrink-0">
                               <Calendar className="w-6 h-6" />
                            </div>
                            <div className="min-w-0">
                               <h3 className="font-black text-foreground text-lg tracking-tight group-hover:text-primary transition-colors truncate">{r.event?.title}</h3>
                               <div className="flex items-center gap-4 mt-1">
                                  <div className="flex items-center gap-1.5 text-xs text-muted-foreground font-bold">
                                     <Clock className="w-3.5 h-3.5" /> {r.event?.date}
                                  </div>
                                  <div className="flex items-center gap-1.5 text-xs text-muted-foreground font-bold">
                                     <MapPin className="w-3.5 h-3.5" /> {r.event?.venue}
                                  </div>
                               </div>
                            </div>
                         </div>
                         <div className="flex items-center gap-3 w-full md:w-auto">
                            <Link to={`/events/${r.eventId}`} className="flex-1 md:flex-none px-6 py-2.5 rounded-xl bg-primary/10 text-primary text-xs font-black uppercase tracking-widest hover:bg-primary hover:text-white transition-all text-center">
                               View Event
                            </Link>
                            <button 
                              onClick={() => handleCancelRegistration(r.id)}
                              disabled={actionLoading === r.id}
                              className="w-11 h-11 flex items-center justify-center rounded-xl bg-destructive/10 text-destructive hover:bg-destructive hover:text-white transition-all active:scale-95"
                            >
                               {actionLoading === r.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <XCircle className="w-5 h-5" />}
                            </button>
                         </div>
                      </div>
                    )) : (
                      <div className="py-20 bg-card rounded-3xl border border-dashed border-border flex flex-col items-center">
                         <Calendar className="w-16 h-16 text-muted-foreground opacity-20 mb-4" />
                         <p className="text-muted-foreground font-bold tracking-tight">No events registered yet.</p>
                         <Link to="/student/explore" className="mt-4 text-primary text-sm font-black uppercase tracking-widest underline underline-offset-8">Browse Events</Link>
                      </div>
                    )}
                  </div>
                </motion.div>
              )}

              {activeSection === "wishlist" && (
                 <motion.div
                   key="wishlist"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   className="space-y-6"
                 >
                   <div className="flex items-center justify-between mb-2">
                    <h2 className="text-2xl font-black text-foreground tracking-tighter">Event Wishlist</h2>
                    <span className="bg-accent/10 px-3 py-1 rounded-lg text-accent text-[10px] font-black uppercase tracking-widest">{wishlist.length} Saved</span>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    {wishlist.length > 0 ? wishlist.map((item: any) => (
                      <div key={item._id} className="bg-card rounded-3xl border border-border/50 overflow-hidden shadow-xl shadow-foreground/5 hover:border-accent/30 transition-all group relative">
                         <div className="h-40 relative">
                            <img src={item.imageUrl || "https://images.unsplash.com/photo-1501281668745-f7f57925c3b4?w=800"} alt={item.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                            <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                            <button 
                               onClick={() => handleRemoveFromWishlist(item._id)}
                               disabled={actionLoading === item._id}
                               className="absolute top-4 right-4 w-10 h-10 rounded-xl bg-white/20 backdrop-blur-md flex items-center justify-center text-white hover:bg-destructive hover:text-white transition-all shadow-xl"
                            >
                               {actionLoading === item._id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-5 h-5" />}
                            </button>
                         </div>
                         <div className="p-6">
                            <h3 className="font-black text-foreground text-lg tracking-tight mb-2 truncate group-hover:text-accent transition-colors">{item.title}</h3>
                            <div className="flex items-center gap-2 text-xs text-muted-foreground font-bold mb-6">
                               <Calendar className="w-3.5 h-3.5" /> {item.date}
                            </div>
                            <Link to={`/events/${item._id}`} className="w-full flex items-center justify-center gap-2 h-11 rounded-xl bg-accent text-white text-xs font-black uppercase tracking-widest shadow-lg shadow-accent/20 hover:bg-accent/90 transition-all active:scale-95">
                               View Event <ExternalLink className="w-3.5 h-3.5" />
                            </Link>
                         </div>
                      </div>
                    )) : (
                      <div className="col-span-2 py-20 bg-card rounded-3xl border border-dashed border-border flex flex-col items-center">
                         <Heart className="w-16 h-16 text-muted-foreground opacity-20 mb-4" />
                         <p className="text-muted-foreground font-bold tracking-tight">Your wishlist is empty.</p>
                      </div>
                    )}
                  </div>
                 </motion.div>
              )}

              {activeSection === "tickets" && (
                 <motion.div
                   key="tickets"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   className="space-y-6"
                 >
                   <div className="flex items-center justify-between mb-2">
                    <h2 className="text-2xl font-black text-foreground tracking-tighter">My Event Tickets</h2>
                    <span className="bg-primary/10 px-3 py-1 rounded-lg text-primary text-[10px] font-black uppercase tracking-widest">{tickets.length} Tickets</span>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {tickets.length > 0 ? tickets.map((t: any) => (
                      <div key={t.id} className="bg-card rounded-3xl border border-border/50 overflow-hidden shadow-xl shadow-foreground/5 flex flex-col relative group">
                         <div className="p-6 pb-8 border-b border-border/50 border-dashed relative">
                            {/* Ticket cutouts */}
                            <div className="absolute -left-3 bottom-[-12px] w-6 h-6 rounded-full bg-background border-r border-t border-border/50 -rotate-45" />
                            <div className="absolute -right-3 bottom-[-12px] w-6 h-6 rounded-full bg-background border-l border-t border-border/50 rotate-45" />
                            
                            <div className="flex justify-between items-start mb-6">
                               <div>
                                  <span className="bg-green-500/10 text-green-500 text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded-md mb-3 inline-block">Confirmed</span>
                                  <h3 className="font-black text-foreground text-xl tracking-tight line-clamp-2">{t.event?.title}</h3>
                               </div>
                               <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shrink-0">
                                  <CheckCircle className="w-6 h-6" />
                               </div>
                            </div>
                            
                            <div className="grid grid-cols-2 gap-4">
                               <div>
                                  <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block mb-1 opacity-60">Date & Time</span>
                                  <p className="text-sm font-bold text-foreground flex items-center gap-1.5"><Clock className="w-3.5 h-3.5 text-primary" /> {t.event?.date}</p>
                               </div>
                               <div>
                                  <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block mb-1 opacity-60">Venue</span>
                                  <p className="text-sm font-bold text-foreground flex items-center gap-1.5"><MapPin className="w-3.5 h-3.5 text-primary" /> {t.event?.venue || 'TBA'}</p>
                               </div>
                            </div>
                         </div>
                         
                         <div className="p-6 bg-muted/20 flex items-center justify-between">
                            <div>
                               <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block mb-1 opacity-60">Ticket ID</span>
                               <p className="font-mono text-sm font-bold text-foreground bg-muted px-2 py-1 rounded-md">{t.ticketNumber || `TCK-${t.id.substring(0, 8).toUpperCase()}`}</p>
                            </div>
                            <div className="w-16 h-16 bg-white p-1 rounded-lg shadow-sm">
                               {/* Mock QR Code using CSS since we don't have a library */}
                               <div className="w-full h-full bg-[url('https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=EventraTicket')] bg-cover bg-center opacity-80 mix-blend-multiply" />
                            </div>
                         </div>
                      </div>
                    )) : (
                      <div className="col-span-2 py-20 bg-card rounded-3xl border border-dashed border-border flex flex-col items-center">
                         <div className="w-20 h-20 rounded-full bg-muted flex items-center justify-center mb-6">
                            <CheckCircle className="w-10 h-10 text-muted-foreground opacity-30" />
                         </div>
                         <h3 className="text-xl font-black text-foreground tracking-tighter mb-2">No Tickets Found</h3>
                         <p className="text-muted-foreground font-medium text-center max-w-md">You don't have any event tickets yet. Register for an event to get your access tickets.</p>
                         <Link to="/student/explore" className="mt-6 px-6 py-2.5 rounded-xl bg-primary text-white text-xs font-black uppercase tracking-widest hover:bg-primary/90 transition-all active:scale-95 shadow-lg shadow-primary/20">Find Events</Link>
                      </div>
                    )}
                  </div>
                 </motion.div>
              )}

              {activeSection === "settings" && (
                 <motion.div
                   key="settings"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   className="space-y-6"
                 >
                   <div className="bg-card rounded-3xl border border-border/50 p-10 text-center">
                      <SettingsIcon className="w-16 h-16 text-muted-foreground opacity-20 mx-auto mb-6" />
                      <h2 className="text-2xl font-black text-foreground tracking-tighter mb-2 italic">Account Security</h2>
                      <p className="text-muted-foreground max-w-sm mx-auto font-medium">Profile editing and password change features are coming in the next update.</p>
                      
                      <div className="mt-10 pt-10 border-t border-border/50">
                         <Link to="/settings" className="px-8 py-3.5 rounded-2xl bg-muted font-black text-xs uppercase tracking-widest hover:bg-primary hover:text-white transition-all">Go to Global Settings</Link>
                      </div>
                   </div>
                 </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
};

export default Profile;

